export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours22Locale { questions: Question[]; }

const questionsFr: Question[] = [
  // Définition et principe
  { q: "Qu'est-ce que la réharmonisation ?", opts: ["Transposer une mélodie dans une autre tonalité","Remplacer les accords d'une progression tout en conservant la mélodie","Ajouter des extensions à tous les accords","Changer le rythme harmonique"], a: 1, fb: "La réharmonisation consiste à remplacer les accords d'une progression existante par d'autres accords, tout en conservant la mélodie intacte. C'est l'art de modifier 'le sol' sans toucher 'le toit'." },
  { q: "Quelle est la contrainte fondamentale de la réharmonisation ?", opts: ["Les nouveaux accords doivent être dans la même tonalité","La mélodie doit rester compatible avec les nouveaux accords","Le rythme harmonique doit doubler","Les accords doivent être plus complexes"], a: 1, fb: "La mélodie doit rester compatible avec les nouveaux accords — c'est la contrainte fondamentale. La note de mélodie doit être consonante avec chaque nouvel accord (fondamentale, tierce, quinte, 7te, 9te, 11te, 13te)." },
  { q: "Qu'est-ce qu'un 'guide-tone' ?", opts: ["La note la plus haute de l'accord","La tierce et la septième d'un accord de dominante","La fondamentale et la quinte","La 9te d'un accord étendu"], a: 1, fb: "Les guide-tones sont la tierce et la septième d'un accord de dominante. Ces deux notes définissent le triton caractéristique — elles sont au cœur des substitutions tritoniques." },
  { q: "Quel compositeur est célèbre pour ses réharmonisations impressionnistes ?", opts: ["Beethoven","Mozart","Bill Evans","Haendel"], a: 2, fb: "Bill Evans (1929–1980) est l'un des plus grands maîtres de la réharmonisation. Ses réharmonisations de standards jazz, utilisant emprunts modaux et harmonisation parallèle, ont révolutionné le piano jazz." },
  { q: "Pourquoi réharmoniser ?", opts: ["Pour faciliter la lecture","Pour corriger une erreur harmonique","Pour enrichir la couleur, créer de l'intérêt, personnaliser l'arrangement","Pour raccourcir la progression"], a: 2, fb: "On réharmonise pour enrichir la couleur harmonique, créer de l'intérêt ou de la surprise, personnaliser un arrangement, ou exprimer une vision musicale différente." },
  { q: "Une note de mélodie est 'compatible' avec un accord si :", opts: ["Elle est la fondamentale de l'accord uniquement","Elle est fondamentale, 3ce, 5te, 7te, 9te, #11 ou 13te de l'accord","Elle n'est pas dans l'accord","Elle est la plus haute de l'accord"], a: 1, fb: "Une note est compatible si elle fait partie des extensions de l'accord : fondamentale, tierce, quinte, 7te, 9te, 11te augmentée (#4), 13te. Les notes de tension forte (9te mineure, 11te juste sur accord majeur) sont généralement à éviter." },
  { q: "Quelle est l'avoid note classique sur un accord Maj7 ?", opts: ["La 9te","La 4te juste (11te naturelle)","La 6te majeure","La 7te mineure"], a: 1, fb: "La 4te juste (11te naturelle) est l'avoid note classique sur un accord Maj7. En CMaj7, F est à ½ ton de E (tierce de l'accord) — dissonance de ½ ton très forte. On préfère utiliser F# (#11) en jazz." },
  { q: "Quel mouvement de basse est souvent créé par une bonne réharmonisation ?", opts: ["Basse statique","Basse par sauts d'octave","Basse avec mouvement chromatique ou conjoint","Basse par quintes"], a: 2, fb: "Une réharmonisation efficace crée souvent un mouvement de basse chromatique ou conjoint — ex. D → D♭ → C dans la substitution tritonique sur Autumn Leaves. Ce mouvement fluide est une signature des meilleures réharmonisations." },
  { q: "La réharmonisation est particulièrement utilisée dans :", opts: ["La musique baroque","La musique sérielle","Le jazz et la musique impressionniste","La polyphonie médiévale"], a: 2, fb: "La réharmonisation est au cœur du jazz (Bill Evans, Miles Davis, Brad Mehldau) et de la musique impressionniste (Debussy, Ravel). Ces styles partagent un goût pour la couleur harmonique plutôt que la tension-résolution." },
  { q: "Dans une réharmonisation, quel paramètre ne change PAS par définition ?", opts: ["Les accords","La mélodie","Le rythme harmonique","La tonalité d'ensemble"], a: 1, fb: "Par définition, la réharmonisation conserve la mélodie intacte. C'est le principe fondateur : on change les accords 'sous' la mélodie, qui reste la même." },
  { q: "La notion d'harmonie 'fonctionnelle' vs harmonie 'coloriste' est centrale car :", opts: ["L'une est jazz et l'autre classique","L'harmonisation fonctionnelle crée tension-résolution, la coloriste crée des atmosphères","La coloriste est uniquement modale","La fonctionnelle est uniquement diatonique"], a: 1, fb: "Harmonie fonctionnelle : les accords créent tension–résolution. Harmonie coloriste : les accords sont des couleurs autonomes. La réharmonisation peut aller vers plus de colorisme (Evans, Debussy) ou rester fonctionnelle (bebop)." },
  { q: "Peut-on réharmoniser en modifiant le rythme harmonique ?", opts: ["Non, le rythme harmonique ne fait pas partie de la réharmonisation","Oui — accélérer (plus d'accords) ou ralentir (pédales) est aussi une forme de réharmonisation","Oui, mais uniquement en accélérant","Non, la mélodie empêche tout changement de rythme"], a: 1, fb: "Le rythme harmonique (fréquence des changements d'accords) peut être modifié dans une réharmonisation. Une pédale (accord tenu) ou une subdivision plus dense sont des outils de réharmonisation à part entière." },
  { q: "Une réharmonisation peut-elle modifier la tonalité d'une pièce ?", opts: ["Non, jamais","Oui — une réharmonisation peut induire une nouvelle tonalité","Oui, mais seulement vers le relatif mineur","Seulement si on change aussi le mode"], a: 1, fb: "Oui — une réharmonisation audacieuse peut glisser vers une nouvelle tonalité implicite. C'est d'ailleurs une manière de créer une modulation progressive et fluide, sans rupture brutale." },
  { q: "Quel style musical a popularisé la réharmonisation comme technique d'arrangement codifiée ?", opts: ["La musique classique baroque","Le jazz des années 1950–1970","La musique folk","La musique contemporaine dodécaphonique"], a: 1, fb: "Le jazz des années 1950–1970 — particulièrement le jazz modal et post-bop — a popularisé la réharmonisation systématique. Miles Davis, Bill Evans et leurs contemporains ont élevé cette technique au rang d'art." },
  { q: "Quelle est la différence entre substitution et réharmonisation ?", opts: ["Ce sont des synonymes exacts","La substitution remplace un accord, la réharmonisation transforme toute une progression","La substitution est plus avancée","La réharmonisation ne change pas la mélodie"], a: 1, fb: "La substitution désigne le remplacement d'un accord spécifique (ex. G7 → D♭7). La réharmonisation est un terme plus large qui peut transformer toute une progression — elle englobe la substitution et d'autres techniques." },
  // Substitution diatonique
  { q: "Qu'est-ce que la substitution diatonique ?", opts: ["Remplacer un accord par son accord de dominante","Remplacer un accord par un autre accord diatonique qui partage des notes communes","Ajouter la 7te à tous les accords","Remplacer les accords mineurs par des majeurs"], a: 1, fb: "La substitution diatonique remplace un accord par un autre accord de la même gamme (diatonique) qui partage des notes communes. Les accords à distance de tierce sont les meilleurs candidats — ils partagent 2 notes sur 3." },
  { q: "Pourquoi les accords à distance de tierce sont-ils de bons substituts diatoniques ?", opts: ["Ils ont la même fondamentale","Ils partagent 2 notes communes sur 3 (triade)","Ils sont toujours de la même qualité","Ils créent la même couleur exactement"], a: 1, fb: "En C majeur : CMaj (C E G) et Em (E G B) partagent E et G. Cette communauté de notes garantit que la mélodie reste compatible — c'est le principe de la substitution diatonique." },
  { q: "Quel accord est le substitut diatonique naturel de I (accord de tonique) ?", opts: ["IV","V","VI (relatif mineur)","VII"], a: 2, fb: "Le VIm (relatif mineur) est le substitut diatonique naturel de I. En C majeur : Am est le substitut de CMaj — ils partagent C et E, deux des trois notes de la triade." },
  { q: "En C majeur, quel accord peut substituer Dm7 par substitution diatonique ?", opts: ["GMaj7","Fmaj7","Bm7♭5","CMaj7"], a: 1, fb: "Fmaj7 peut substituer Dm7 — ils partagent F, A, C (3 notes communes). Fmaj7 = F A C E ; Dm7 = D F A C. Trois notes communes : F, A, C." },
  { q: "La progression II–V–I (Dm7–G7–CMaj7) réharmonisée en Fmaj7–Em7–CMaj7 illustre :", opts: ["Substitution tritonique","Substitution diatonique des deux premiers accords","Emprunt modal","Harmonisation parallèle"], a: 1, fb: "Fmaj7 substitue Dm7 (3 notes communes : F A C), Em7 substitue G7 (3 notes communes : G B D). Double substitution diatonique — la tension du II–V est diffusée, la couleur devient plus modale." },
  { q: "En G majeur, quel accord est le substitut diatonique naturel de GMaj7 (I) ?", opts: ["Am7 (II)","Bm7 (III)","Em7 (VI)","D7 (V)"], a: 2, fb: "Em7 (VIm) est le substitut diatonique naturel de GMaj7 (I) en G majeur. GMaj7 = G B D F# ; Em7 = E G B D. Ils partagent G, B, D — trois notes communes." },
  { q: "Quel risque principal comporte la substitution diatonique ?", opts: ["Sortir de la tonalité","Perdre la tension harmonique de l'original (le V7 perd sa fonction de dominante)","Rendre la progression trop complexe","Créer des mouvements de basse parallèles"], a: 1, fb: "En substituant V7, on peut perdre la tension de dominante. C'est un risque (moins de tension) mais aussi un avantage (atmosphère plus modale, moins tonale)." },
  { q: "Em7 → G7 en C majeur illustre quelle relation diatonique ?", opts: ["Substitut à distance de 2de","IIIm substitue V7 (partagent G, B, D)","Substitut à distance de quinte","Substitut de sous-dominante"], a: 1, fb: "Em7 et G7 partagent G, B, D — trois notes communes. Em7 peut substituer G7 en créant une couleur moins tendue. C'est la substitution par le IIIm du Ve degré." },
  { q: "La substitution diatonique préserve toujours :", opts: ["La qualité (majeur/mineur) de l'accord original","La fonction harmonique de l'accord original","La tonalité générale de la progression","La note de basse originale"], a: 2, fb: "La substitution diatonique reste dans la même gamme — elle préserve la tonalité générale. En revanche, elle peut modifier la fonction et la qualité de l'accord." },
  // Substitution tritonique
  { q: "Qu'est-ce que la substitution tritonique ?", opts: ["Remplacer tout accord par sa transposition de triton","Remplacer V7 par l'accord de dominante situé un triton plus bas","Ajouter un triton à l'accord de dominante","Utiliser des accords augmentés"], a: 1, fb: "La substitution tritonique remplace V7 par l'accord de dominante situé un triton plus bas (6 demi-tons). G7 → D♭7. Ces deux accords partagent leur guide-tone (tierce et septième inversées)." },
  { q: "Pourquoi G7 et D♭7 sont-ils des substituts tritoniques l'un de l'autre ?", opts: ["Ils ont la même fondamentale octaviée","Ils partagent le même guide-tone : B/C♭ et F (enharmoniques)","Ils sont tous deux en mode dorien","Ils ont la même quinte"], a: 1, fb: "G7 : guide-tone B (3ce) et F (7te). D♭7 : guide-tone F (3ce) et C♭/B (7te). B et C♭ sont enharmoniques, F est commun. Ces deux notes de tension sont partagées." },
  { q: "Quel est le substitut tritonique de C7 ?", opts: ["F7","G♭7","G7","E♭7"], a: 1, fb: "G♭7 est le substitut tritonique de C7. Distance C → G♭ = 6 demi-tons. C7 : guide-tone E (3ce) et B♭ (7te) ; G♭7 : guide-tone B♭ (3ce) et F♭/E (7te)." },
  { q: "Quel effet crée la substitution tritonique sur la basse ?", opts: ["Basse qui monte d'une quinte","Basse chromatique descendante (ex. G → D♭ → C)","Basse statique","Basse qui descend par quintes"], a: 1, fb: "La substitution tritonique crée une basse chromatique descendante. Dans II–V–I en C avec sub tri sur V : D → D♭ → C. Ce mouvement de ½ ton D♭→C est très expressif et fluide." },
  { q: "La substitution tritonique s'applique principalement à :", opts: ["Tous les types d'accords","Les accords de tonique (Maj7)","Les accords de dominante (7te)","Les accords de sous-dominante mineurs"], a: 2, fb: "La substitution tritonique s'applique principalement aux accords de dominante (7te). Le triton interne de V7 (guide-tone) est la condition nécessaire." },
  { q: "Dans Autumn Leaves en Cm, la substitution tritonique de G7 donne :", opts: ["C7","F#7 / G♭7","D♭7","A♭7"], a: 2, fb: "G7 → D♭7 (triton de G). La basse devient : Dm7♭5 (D) → D♭7 (D♭) → Cm (C) — mouvement chromatique D → D♭ → C. C'est l'une des réharmonisations les plus célèbres du jazz." },
  { q: "La substitution tritonique a été développée principalement dans :", opts: ["La musique baroque (XVIIe siècle)","Le jazz bebop (années 1940–1950)","La musique sérielle (XXe siècle)","L'impressionnisme (début XXe)"], a: 1, fb: "La substitution tritonique a été développée dans le bebop des années 1940–1950, popularisée par Charlie Parker, Dizzy Gillespie et Thelonious Monk." },
  { q: "Quel est le substitut tritonique de D7 ?", opts: ["G♯7 / A♭7","A7","E♭7 / D♯7","F7"], a: 0, fb: "A♭7 est le substitut tritonique de D7. Distance D → A♭ = 6 demi-tons. Guide-tones de D7 : F# (3ce) et C (7te). Guide-tones de A♭7 : C (3ce) et G♭ (7te = F# enharmonique)." },
  { q: "Quel est le substitut tritonique de F7 ?", opts: ["B7","C7","E7","G7"], a: 0, fb: "B7 est le substitut tritonique de F7. Distance F → B = 6 demi-tons. Guide-tones de F7 : A (3ce) et E♭ (7te). Guide-tones de B7 : D# (3ce = E♭ enharmonique) et A (7te)." },
  { q: "Peut-on appliquer la substitution tritonique à une dominante secondaire ?", opts: ["Non, uniquement au V7 principal","Oui — le V7/II (A7 en C) peut être remplacé par E♭7","Oui, mais uniquement si c'est le V7/IV","Seulement si la progression dure 2 mesures minimum"], a: 1, fb: "Oui — la substitution tritonique s'applique à tout accord de dominante, y compris les dominantes secondaires. V7/II = A7 en C majeur → E♭7 (triton de A)." },
  // Emprunt modal
  { q: "Qu'est-ce qu'un emprunt modal ?", opts: ["Utiliser des gammes modales dans une progression tonale","Emprunter un accord au mode parallèle (même tonique, mode différent)","Transposer un accord dans un autre mode","Utiliser le mode lydien sur un accord majeur"], a: 1, fb: "L'emprunt modal consiste à emprunter un accord au mode parallèle — même tonique, mode différent. En C majeur, Fm7 est emprunté à C mineur. La tonique reste identique, on emprunte la couleur du mineur." },
  { q: "En C majeur, quels accords sont typiquement empruntés au mode mineur parallèle ?", opts: ["Am7, Em7, Dm7","♭VIMaj7, ♭VIIMaj7, IVm7","II7, III7, VI7","VIIdim, IVdim, IIdim"], a: 1, fb: "Les emprunts classiques du mineur parallèle en C majeur : Fm7 (IVm), A♭Maj7 (♭VI), B♭Maj7 (♭VII). Ces accords bémolisés introduisent des ♭ étrangers à C majeur mais naturels dans C mineur." },
  { q: "L'accord ♭VIIMaj7 en C majeur (B♭Maj7) est emprunté à :", opts: ["G mixolydien","C mineur (éolien)","F lydien","D dorien"], a: 1, fb: "B♭Maj7 = ♭VIIMaj7 en C majeur. En C mineur naturel (éolien), le VIIe degré est B♭ — c'est l'accord ♭VII naturel du mineur, emprunté au mode mineur parallèle." },
  { q: "La succession CMaj7 → Cm7 illustre :", opts: ["Substitution tritonique","Emprunt modal (même tonique, couleur majeur → mineur)","Harmonisation parallèle","Substitution diatonique"], a: 1, fb: "CMaj7 → Cm7 : même fondamentale C, passage du mode majeur au mode mineur. C'est le cœur de l'emprunt modal — même tonique, couleur différente. Bill Evans exploite ce geste dans Peace Piece." },
  { q: "Bill Evans utilise l'emprunt modal dans Peace Piece en :", opts: ["Remplaçant G7 par D♭7","Empruntant Cm7 et Fm7 au mode C mineur sur une pédale de C","Utilisant des gammes pentatoniques","Transposant la mélodie en mode dorien"], a: 1, fb: "Dans Peace Piece, Evans maintient C comme pédale de basse et emprunte Cm7 et Fm7 au C mineur parallèle. Ce balancement Maj7 ↔ m7 crée la couleur méditative caractéristique de la pièce." },
  { q: "En G majeur, quel accord est l'emprunt modal ♭VIMaj7 ?", opts: ["E♭Maj7","FMaj7","B♭Maj7","A♭Maj7"], a: 0, fb: "♭VI en G = E♭. E♭Maj7 est emprunté à G mineur (G éolien) où le VIe degré est E♭. C'est un accord très expressif dans une progression en G majeur." },
  { q: "L'accord IVm dans une tonalité majeure (ex. Fm dans C) crée quel effet ?", opts: ["Clarté et stabilité renforcée","Une couleur sombre inattendue due à la tierce mineure et la 7te bémolisée empruntées","Plus de tension de dominante","Résolution plagale pure"], a: 1, fb: "Fm7 = F A♭ C E♭. Le A♭ et le E♭ sont empruntés à C mineur. Ces notes ♭ créent une couleur sombre inattendue dans un contexte majeur — c'est précisément l'effet recherché." },
  { q: "Peut-on emprunter des accords à d'autres modes que le mineur parallèle ?", opts: ["Non, uniquement au mineur parallèle","Oui — phrygien, lydien, dorien, etc. sont aussi des sources d'emprunts","Oui, mais uniquement dans le jazz","Seulement pour les accords de sous-dominante"], a: 1, fb: "Oui — on peut emprunter à n'importe quel mode parallèle. ♭II (de phrygien), #IV (de lydien), ♭VI (de mixolydien ou éolien), etc. Plus l'emprunt vient d'un mode éloigné, plus la couleur est surprenante." },
  // Harmonisation parallèle
  { q: "Qu'est-ce que l'harmonisation parallèle ?", opts: ["Harmoniser une mélodie avec deux voix à la tierce","Transposer un accord de même qualité par mouvement conjoint (demi-tons ou tons)","Doubler la mélodie à l'octave inférieure","Utiliser des accords parallèles à distance de quinte"], a: 1, fb: "L'harmonisation parallèle consiste à transposer un bloc d'accords (de même qualité) par mouvement conjoint. CMaj7 → BMaj7 → B♭Maj7 : trois Maj7 descendant chromatiquement." },
  { q: "Le parallélisme chromatique avec des accords Maj7 est associé à :", opts: ["Le contrepoint baroque strict","L'impressionnisme français et le jazz modal (Debussy, Bill Evans)","La musique sérielle","Le blues traditionnel"], a: 1, fb: "Le parallélisme chromatique avec des Maj7 est la signature de l'impressionnisme (Debussy) et du jazz modal (Bill Evans, Herbie Hancock). C'est l'une des sonorités les plus 'contemporaines' en harmonie." },
  { q: "Dans une harmonisation parallèle, la mélodie :", opts: ["Doit impérativement se mouvoir conjointement","Peut rester sur une note tenue pendant que les accords bougent","Doit suivre la même direction que les accords","Doit être doublée à la tierce inférieure"], a: 1, fb: "La note de mélodie peut rester tenue (pédale mélodique) pendant que les accords descendent chromatiquement. Cette tension entre mélodie fixe et harmonie mobile est très expressive." },
  { q: "CMaj7 → BMaj7 → B♭Maj7 illustre une harmonisation parallèle :", opts: ["Par tons entiers","Chromatique descendante (½ ton ½ ton)","Par tierces descendantes","Par quintes descendantes"], a: 1, fb: "C → B → B♭ : chaque fondamentale descend d'un demi-ton. C'est le parallélisme chromatique — le plus expressif dans le jazz moderne." },
  { q: "Quel compositeur classique a popularisé les accords en glissement parallèle ?", opts: ["Debussy","Beethoven","Brahms","Schoenberg"], a: 0, fb: "Claude Debussy a popularisé les accords en glissement parallèle dans l'impressionnisme. Dans 'La cathédrale engloutie', des blocs parallèles créent la couleur organique caractéristique." },
  { q: "Pourquoi l'harmonisation parallèle 'libère' les accords de leurs fonctions tonales ?", opts: ["Elle élimine les accords de dominante","Les accords parallèles créent une couleur, pas une tension-résolution — pensée coloriste","Elle change la tonalité à chaque accord","Elle utilise uniquement des accords de sous-dominante"], a: 1, fb: "Dans le parallélisme, les accords ne jouent plus leur rôle fonctionnel (T/SD/D) — chaque accord est une couleur à part entière. C'est la pensée modale/coloriste plutôt que fonctionnelle/tonale." },
  // Analyse comparative
  { q: "Comparer substitution diatonique et tritonique : quelle affirmation est vraie ?", opts: ["La diatonique s'applique à V7, la tritonique à tous les accords","La tritonique s'applique spécifiquement à V7 ; la diatonique s'applique à tous les degrés","Les deux s'appliquent uniquement aux accords mineurs","La diatonique sort de la gamme, la tritonique non"], a: 1, fb: "La substitution tritonique cible spécifiquement V7 (et les dominantes secondaires). La substitution diatonique s'applique à n'importe quel degré de la gamme." },
  { q: "Quelle technique crée le mouvement de basse le plus chromatique ?", opts: ["Substitution diatonique","Emprunt modal","Substitution tritonique","Harmonisation parallèle par tons"], a: 2, fb: "La substitution tritonique crée le mouvement de basse chromatique le plus direct : V7 → sub(V7) → I donne ½ ton → I (ex. G → D♭ → C). C'est le plus expressif et le plus 'jazz'." },
  { q: "Quelle technique est la plus 'douce' (moins chromatique, dans la tonalité) ?", opts: ["Substitution tritonique","Emprunt modal","Harmonisation parallèle chromatique","Substitution diatonique"], a: 3, fb: "La substitution diatonique reste entièrement dans la gamme — elle ne sort jamais de la tonalité. C'est la technique la moins chromatique, la plus 'intérieure' à la tonalité." },
  { q: "Bill Evans est né et mort en :", opts: ["1910–1975","1929–1980","1945–1990","1920–1965"], a: 1, fb: "Bill Evans (1929–1980) est l'un des pianistes jazz les plus influents du XXe siècle. Ses innovations harmoniques — réharmonisations, voicings en clusters, emprunts modaux — ont défini le piano jazz moderne." },
  { q: "Quel album de Miles Davis (avec Bill Evans) est fondateur du jazz modal ?", opts: ["A Love Supreme","Kind of Blue (1959)","Bitches Brew","Sketches of Spain"], a: 1, fb: "Kind of Blue (1959) est l'album de jazz le plus vendu de tous les temps. Bill Evans a contribué aux notes de programme. So What, Flamenco Sketches — chacun illustre une approche modale distincte." },
  { q: "Brad Mehldau est particulièrement connu pour ses réharmonisations de :", opts: ["Bach et Haendel uniquement","Standards jazz et chansons pop/rock (Radiohead, Beatles)","Musiques de films","Opéras italiens"], a: 1, fb: "Brad Mehldau (né 1970) est célèbre pour ses réinterprétations jazz de pop et rock — Radiohead (Exit Music for a Film), Beatles (Blackbird). Ses réharmonisations transforment ces mélodies connues en œuvres jazz sophistiquées." },
  { q: "La progression 'Coltrane changes' (Giant Steps) utilise quel principe ?", opts: ["Substitutions diatoniques uniquement","Cycle de tierces majeures divisant l'octave en 3 parties égales","Harmonisation parallèle en blocs","Emprunts modaux au mode phrygien"], a: 1, fb: "John Coltrane dans Giant Steps (1960) divise l'octave en trois tierces majeures : B – G – E♭ – B. Chaque tonalité dure seulement 2 beats. C'est une réharmonisation radicale qui remplace le cycle de quintes." },
  { q: "Quel pianiste classique a fortement influencé l'harmonisation parallèle jazz ?", opts: ["Rachmaninov","Debussy (impressionnisme français)","Brahms","Bartók"], a: 1, fb: "Claude Debussy (1862–1918) a directement influencé le jazz via ses accords parallèles, gammes par tons et couleurs harmoniques non fonctionnelles. Bill Evans citait Debussy comme influence majeure." },
  { q: "Quelle affirmation décrit le mieux la réharmonisation comme outil créatif ?", opts: ["C'est une technique de correction d'harmonies incorrectes","C'est l'art de transformer la couleur harmonique d'une œuvre tout en respectant sa mélodie — une signature personnelle","C'est uniquement une technique pédagogique","C'est une technique de simplification pour débutants"], a: 1, fb: "La réharmonisation est une signature musicale personnelle. Bill Evans, Miles Davis, Keith Jarrett, Brad Mehldau — chacun a développé un langage reconnaissable. C'est l'art de transformer une œuvre en expression personnelle, en respectant la mélodie." },
  { q: "Pour réharmoniser une progression gospel I–IV–I–V, quelle technique serait idiomatique ?", opts: ["Substitutions tritoniques sur chaque accord","Emprunts modaux (IVm, ♭VII) pour ajouter couleur mineure dans un contexte majeur","Harmonisation parallèle chromatique","Coltrane Changes"], a: 1, fb: "Le gospel utilise fréquemment les emprunts modaux — IVm (Fm dans C), ♭VI, ♭VII — qui introduisent la couleur bleue dans un contexte majeur. La progression I – IVm – I – V est caractéristique du gospel." },
  { q: "Lequel illustre une double technique : emprunt modal + harmonisation parallèle ?", opts: ["Dm7 → G7 → CMaj7","CMaj7 → Cm7 → Fm7 puis Fm7 → EMaj7 → E♭Maj7","G7 → D♭7 → C","Am7 → Fmaj7 → G7"], a: 1, fb: "CMaj7 → Cm7 → Fm7 : emprunt modal (C mineur). Puis Fm7 → EMaj7 → E♭Maj7 : harmonisation parallèle chromatique descendante. La combinaison crée une progression très 'Bill Evans'." },
];

const questionsEn: Question[] = [
  { q: "What is reharmonization?", opts: ["Transposing a melody to another key","Replacing the chords of a progression while keeping the melody","Adding extensions to all chords","Changing the harmonic rhythm"], a: 1, fb: "Reharmonization consists of replacing the chords of an existing progression with other chords, while keeping the melody intact. It is the art of changing 'the ground' without touching 'the roof'." },
  { q: "What is the fundamental constraint of reharmonization?", opts: ["The new chords must be in the same key","The melody must remain compatible with the new chords","The harmonic rhythm must double","The chords must be more complex"], a: 1, fb: "The melody must remain compatible with the new chords — this is the fundamental constraint. The melody note must be consonant with each new chord (root, third, fifth, 7th, 9th, 11th, 13th)." },
  { q: "What is a 'guide-tone'?", opts: ["The highest note of the chord","The third and seventh of a dominant chord","The root and fifth","The 9th of an extended chord"], a: 1, fb: "Guide-tones are the third and seventh of a dominant chord. These two notes define the characteristic tritone — they are at the heart of tritone substitutions." },
  { q: "Which composer is famous for his impressionist reharmonizations?", opts: ["Beethoven","Mozart","Bill Evans","Handel"], a: 2, fb: "Bill Evans (1929–1980) is one of the greatest masters of reharmonization. His reharmonizations of jazz standards, using modal borrowings and parallel harmonization, revolutionized jazz piano." },
  { q: "Why reharmonize?", opts: ["To make reading easier","To correct a harmonic error","To enrich the color, create interest, personalize the arrangement","To shorten the progression"], a: 2, fb: "We reharmonize to enrich the harmonic color, create interest or surprise, personalize an arrangement, or express a different musical vision." },
  { q: "A melody note is 'compatible' with a chord if:", opts: ["It is only the root of the chord","It is the root, 3rd, 5th, 7th, 9th, #11 or 13th of the chord","It is not in the chord","It is the highest note of the chord"], a: 1, fb: "A note is compatible if it belongs to the chord's extensions: root, third, fifth, 7th, 9th, augmented 11th (#4), 13th. Strong tension notes (minor 9th, natural 11th on a major chord) are generally to be avoided." },
  { q: "What is the classic avoid note on a Maj7 chord?", opts: ["The 9th","The perfect 4th (natural 11th)","The major 6th","The minor 7th"], a: 1, fb: "The perfect 4th (natural 11th) is the classic avoid note on a Maj7 chord. In CMaj7, F is a half-step from E (the chord's third) — very strong half-step dissonance. In jazz, F# (#11) is preferred." },
  { q: "What bass movement is often created by good reharmonization?", opts: ["Static bass","Bass by octave leaps","Bass with chromatic or stepwise motion","Bass by fifths"], a: 2, fb: "Effective reharmonization often creates chromatic or stepwise bass motion — e.g., D → D♭ → C in the tritone substitution on Autumn Leaves. This fluid movement is a hallmark of the best reharmonizations." },
  { q: "Reharmonization is particularly used in:", opts: ["Baroque music","Serial music","Jazz and impressionist music","Medieval polyphony"], a: 2, fb: "Reharmonization is central to jazz (Bill Evans, Miles Davis, Brad Mehldau) and impressionist music (Debussy, Ravel). These styles share a taste for harmonic color rather than tension-resolution." },
  { q: "In reharmonization, which parameter does NOT change by definition?", opts: ["The chords","The melody","The harmonic rhythm","The overall key"], a: 1, fb: "By definition, reharmonization keeps the melody intact. This is the founding principle: the chords change 'beneath' the melody, which remains the same." },
  { q: "The notion of 'functional' vs 'colorist' harmony is central because:", opts: ["One is jazz and the other classical","Functional harmonization creates tension-resolution, colorist creates atmospheres","Colorist is only modal","Functional is only diatonic"], a: 1, fb: "Functional harmony: chords create tension–resolution. Colorist harmony: chords are autonomous colors. Reharmonization can move toward more colorism (Evans, Debussy) or remain functional (bebop)." },
  { q: "Can you reharmonize by modifying the harmonic rhythm?", opts: ["No, the harmonic rhythm is not part of reharmonization","Yes — accelerating (more chords) or slowing down (pedals) is also a form of reharmonization","Yes, but only by accelerating","No, the melody prevents any change of rhythm"], a: 1, fb: "The harmonic rhythm (frequency of chord changes) can be modified in reharmonization. A pedal (sustained chord) or denser subdivisions are full-fledged reharmonization tools." },
  { q: "Can reharmonization modify the key of a piece?", opts: ["No, never","Yes — reharmonization can induce a new key","Yes, but only toward the relative minor","Only if the mode is also changed"], a: 1, fb: "Yes — a bold reharmonization can drift toward a new implicit key. This is actually a way to create a progressive and fluid modulation, without a brutal break." },
  { q: "Which musical style popularized reharmonization as a codified arranging technique?", opts: ["Baroque classical music","Jazz of the 1950s–1970s","Folk music","Contemporary twelve-tone music"], a: 1, fb: "Jazz of the 1950s–1970s — particularly modal and post-bop jazz — popularized systematic reharmonization. Miles Davis, Bill Evans, and their contemporaries elevated this technique to an art form." },
  { q: "What is the difference between substitution and reharmonization?", opts: ["They are exact synonyms","Substitution replaces one chord, reharmonization transforms an entire progression","Substitution is more advanced","Reharmonization does not change the melody"], a: 1, fb: "Substitution refers to replacing a specific chord (e.g., G7 → D♭7). Reharmonization is a broader term that can transform an entire progression — it encompasses substitution and other techniques." },
  { q: "What is diatonic substitution?", opts: ["Replacing a chord with its dominant chord","Replacing a chord with another diatonic chord that shares common notes","Adding a 7th to all chords","Replacing minor chords with major ones"], a: 1, fb: "Diatonic substitution replaces a chord with another chord from the same scale (diatonic) that shares common notes. Chords a third apart are the best candidates — they share 2 out of 3 notes." },
  { q: "Why are chords a third apart good diatonic substitutes?", opts: ["They have the same root","They share 2 common notes out of 3 (triad)","They are always the same quality","They create exactly the same color"], a: 1, fb: "In C major: CMaj (C E G) and Em (E G B) share E and G. This note sharing guarantees the melody stays compatible — this is the principle of diatonic substitution." },
  { q: "Which chord is the natural diatonic substitute for I (tonic chord)?", opts: ["IV","V","VI (relative minor)","VII"], a: 2, fb: "VIm (relative minor) is the natural diatonic substitute for I. In C major: Am substitutes for CMaj — they share C and E, two of the three notes of the triad." },
  { q: "In C major, which chord can substitute Dm7 by diatonic substitution?", opts: ["GMaj7","Fmaj7","Bm7♭5","CMaj7"], a: 1, fb: "Fmaj7 can substitute Dm7 — they share F, A, C (3 common notes). Fmaj7 = F A C E; Dm7 = D F A C. Three common notes: F, A, C." },
  { q: "The progression II–V–I (Dm7–G7–CMaj7) reharmonized as Fmaj7–Em7–CMaj7 illustrates:", opts: ["Tritone substitution","Diatonic substitution of the first two chords","Modal borrowing","Parallel harmonization"], a: 1, fb: "Fmaj7 substitutes Dm7 (3 common notes: F A C), Em7 substitutes G7 (3 common notes: G B D). Double diatonic substitution — the II–V tension is diffused, the color becomes more modal." },
  { q: "In G major, which chord is the natural diatonic substitute for GMaj7 (I)?", opts: ["Am7 (II)","Bm7 (III)","Em7 (VI)","D7 (V)"], a: 2, fb: "Em7 (VIm) is the natural diatonic substitute for GMaj7 (I) in G major. GMaj7 = G B D F#; Em7 = E G B D. They share G, B, D — three common notes." },
  { q: "What is the main risk of diatonic substitution?", opts: ["Leaving the key","Losing the harmonic tension of the original (V7 loses its dominant function)","Making the progression too complex","Creating parallel bass motion"], a: 1, fb: "By substituting V7, the dominant tension can be lost. This is a risk (less tension) but also an advantage (more modal, less tonal atmosphere)." },
  { q: "Em7 → G7 in C major illustrates what diatonic relationship?", opts: ["Substitute a 2nd apart","IIIm substitutes V7 (sharing G, B, D)","Substitute a fifth apart","Sub-dominant substitute"], a: 1, fb: "Em7 and G7 share G, B, D — three common notes. Em7 can substitute G7, creating a less tense color. This is the substitution by IIIm for the Vth degree." },
  { q: "Diatonic substitution always preserves:", opts: ["The quality (major/minor) of the original chord","The harmonic function of the original chord","The overall key of the progression","The original bass note"], a: 2, fb: "Diatonic substitution stays within the same scale — it preserves the overall key. However, it can modify the function and quality of the chord." },
  { q: "What is tritone substitution?", opts: ["Replacing any chord with its tritone transposition","Replacing V7 with the dominant chord located a tritone below","Adding a tritone to the dominant chord","Using augmented chords"], a: 1, fb: "Tritone substitution replaces V7 with the dominant chord located a tritone below (6 semitones). G7 → D♭7. These two chords share their guide-tones (third and seventh inverted)." },
  { q: "Why are G7 and D♭7 tritone substitutes of each other?", opts: ["They have the same root an octave apart","They share the same guide-tones: B/C♭ and F (enharmonics)","They are both in dorian mode","They have the same fifth"], a: 1, fb: "G7 guide-tones: B (3rd) and F (7th). D♭7 guide-tones: F (3rd) and C♭/B (7th). B and C♭ are enharmonic equivalents, F is shared. These two tension notes are shared." },
  { q: "What is the tritone substitute of C7?", opts: ["F7","G♭7","G7","E♭7"], a: 1, fb: "G♭7 is the tritone substitute of C7. Distance C → G♭ = 6 semitones. C7 guide-tones: E (3rd) and B♭ (7th); G♭7 guide-tones: B♭ (3rd) and F♭/E (7th)." },
  { q: "What effect does tritone substitution create on the bass?", opts: ["Bass that rises a fifth","Descending chromatic bass (e.g., G → D♭ → C)","Static bass","Bass that descends by fifths"], a: 1, fb: "Tritone substitution creates a descending chromatic bass. In II–V–I in C with tritone sub on V: D → D♭ → C. This half-step D♭→C motion is very expressive and fluid." },
  { q: "Tritone substitution applies mainly to:", opts: ["All chord types","Tonic chords (Maj7)","Dominant chords (7th)","Minor subdominant chords"], a: 2, fb: "Tritone substitution applies mainly to dominant chords (7th). The internal tritone of V7 (guide-tone) is the necessary condition." },
  { q: "In Autumn Leaves in Cm, the tritone substitution of G7 gives:", opts: ["C7","F#7 / G♭7","D♭7","A♭7"], a: 2, fb: "G7 → D♭7 (tritone of G). The bass becomes: Dm7♭5 (D) → D♭7 (D♭) → Cm (C) — chromatic motion D → D♭ → C. This is one of the most celebrated reharmonizations in jazz." },
  { q: "Tritone substitution was developed mainly in:", opts: ["Baroque music (17th century)","Bebop jazz (1940s–1950s)","Serial music (20th century)","Impressionism (early 20th century)"], a: 1, fb: "Tritone substitution was developed in the bebop of the 1940s–1950s, popularized by Charlie Parker, Dizzy Gillespie, and Thelonious Monk." },
  { q: "What is the tritone substitute of D7?", opts: ["G#7 / A♭7","A7","E♭7 / D♯7","F7"], a: 0, fb: "A♭7 is the tritone substitute of D7. Distance D → A♭ = 6 semitones. D7 guide-tones: F# (3rd) and C (7th). A♭7 guide-tones: C (3rd) and G♭ (7th = F# enharmonic)." },
  { q: "What is the tritone substitute of F7?", opts: ["B7","C7","E7","G7"], a: 0, fb: "B7 is the tritone substitute of F7. Distance F → B = 6 semitones. F7 guide-tones: A (3rd) and E♭ (7th). B7 guide-tones: D# (3rd = E♭ enharmonic) and A (7th)." },
  { q: "Can tritone substitution be applied to a secondary dominant?", opts: ["No, only to the main V7","Yes — V7/II (A7 in C) can be replaced by E♭7","Yes, but only if it is V7/IV","Only if the progression lasts at least 2 measures"], a: 1, fb: "Yes — tritone substitution applies to any dominant chord, including secondary dominants. V7/II = A7 in C major → E♭7 (tritone of A)." },
  { q: "What is modal borrowing?", opts: ["Using modal scales in a tonal progression","Borrowing a chord from the parallel mode (same tonic, different mode)","Transposing a chord into another mode","Using the Lydian mode on a major chord"], a: 1, fb: "Modal borrowing consists of borrowing a chord from the parallel mode — same tonic, different mode. In C major, Fm7 is borrowed from C minor. The tonic remains the same; the color of the minor is borrowed." },
  { q: "In C major, which chords are typically borrowed from the parallel minor mode?", opts: ["Am7, Em7, Dm7","♭VIMaj7, ♭VIIMaj7, IVm7","II7, III7, VI7","VIIdim, IVdim, IIdim"], a: 1, fb: "Classic borrowings from the parallel minor in C major: Fm7 (IVm), A♭Maj7 (♭VI), B♭Maj7 (♭VII). These flatted chords introduce ♭ accidentals foreign to C major but natural in C minor." },
  { q: "The ♭VIIMaj7 chord in C major (B♭Maj7) is borrowed from:", opts: ["G mixolydian","C minor (aeolian)","F Lydian","D dorian"], a: 1, fb: "B♭Maj7 = ♭VIIMaj7 in C major. In C natural minor (aeolian), the 7th degree is B♭ — this is the natural ♭VII chord of minor, borrowed from the parallel minor mode." },
  { q: "The succession CMaj7 → Cm7 illustrates:", opts: ["Tritone substitution","Modal borrowing (same tonic, major → minor color)","Parallel harmonization","Diatonic substitution"], a: 1, fb: "CMaj7 → Cm7: same root C, shift from major to minor mode. This is the heart of modal borrowing — same tonic, different color. Bill Evans exploits this gesture in Peace Piece." },
  { q: "Bill Evans uses modal borrowing in Peace Piece by:", opts: ["Replacing G7 with D♭7","Borrowing Cm7 and Fm7 from C minor mode on a C pedal","Using pentatonic scales","Transposing the melody to Dorian mode"], a: 1, fb: "In Peace Piece, Evans maintains C as a bass pedal and borrows Cm7 and Fm7 from parallel C minor. This oscillation Maj7 ↔ m7 creates the meditative color characteristic of the piece." },
  { q: "In G major, which chord is the modal borrowing ♭VIMaj7?", opts: ["E♭Maj7","FMaj7","B♭Maj7","A♭Maj7"], a: 0, fb: "♭VI in G = E♭. E♭Maj7 is borrowed from G minor (G aeolian) where the 6th degree is E♭. It is a very expressive chord in a G major progression." },
  { q: "The IVm chord in a major key (e.g., Fm in C) creates what effect?", opts: ["Reinforced clarity and stability","An unexpected dark color due to the borrowed minor third and flatted 7th","More dominant tension","Pure plagal resolution"], a: 1, fb: "Fm7 = F A♭ C E♭. The A♭ and E♭ are borrowed from C minor. These ♭ notes create an unexpected dark color in a major context — this is precisely the intended effect." },
  { q: "Can chords be borrowed from modes other than the parallel minor?", opts: ["No, only from the parallel minor","Yes — phrygian, lydian, dorian, etc. are also sources of borrowings","Yes, but only in jazz","Only for subdominant chords"], a: 1, fb: "Yes — chords can be borrowed from any parallel mode. ♭II (from phrygian), #IV (from lydian), ♭VI (from mixolydian or aeolian), etc. The further the borrowing from a distant mode, the more surprising the color." },
  { q: "What is parallel harmonization?", opts: ["Harmonizing a melody with two voices at the third","Transposing a chord of the same quality by stepwise motion (semitones or whole tones)","Doubling the melody an octave below","Using parallel chords a fifth apart"], a: 1, fb: "Parallel harmonization consists of transposing a chord block (of the same quality) by stepwise motion. CMaj7 → BMaj7 → B♭Maj7: three Maj7 chords descending chromatically." },
  { q: "Chromatic parallelism with Maj7 chords is associated with:", opts: ["Strict baroque counterpoint","French impressionism and modal jazz (Debussy, Bill Evans)","Serial music","Traditional blues"], a: 1, fb: "Chromatic parallelism with Maj7 chords is the signature of impressionism (Debussy) and modal jazz (Bill Evans, Herbie Hancock). It is one of the most 'contemporary' sounds in harmony." },
  { q: "In parallel harmonization, the melody:", opts: ["Must necessarily move stepwise","Can remain on a sustained note while the chords move","Must follow the same direction as the chords","Must be doubled at the lower third"], a: 1, fb: "The melody note can remain sustained (melodic pedal) while the chords descend chromatically. This tension between a fixed melody and moving harmony is very expressive." },
  { q: "CMaj7 → BMaj7 → B♭Maj7 illustrates a parallel harmonization:", opts: ["By whole tones","Chromatic descending (½ tone ½ tone)","By descending thirds","By descending fifths"], a: 1, fb: "C → B → B♭: each root descends by a semitone. This is chromatic parallelism — the most expressive in modern jazz." },
  { q: "Which classical composer popularized sliding parallel chords?", opts: ["Debussy","Beethoven","Brahms","Schoenberg"], a: 0, fb: "Claude Debussy popularized sliding parallel chords in impressionism. In 'La cathédrale engloutie', parallel blocks create the characteristic organ-like color." },
  { q: "Why does parallel harmonization 'free' chords from their tonal functions?", opts: ["It eliminates dominant chords","Parallel chords create color, not tension-resolution — colorist thinking","It changes the key at each chord","It uses only subdominant chords"], a: 1, fb: "In parallelism, chords no longer play their functional role (T/SD/D) — each chord is a color in itself. This is modal/colorist thinking rather than functional/tonal thinking." },
  { q: "Comparing diatonic and tritone substitution: which statement is true?", opts: ["Diatonic applies to V7, tritone applies to all chords","Tritone substitution applies specifically to V7; diatonic applies to all scale degrees","Both apply only to minor chords","Diatonic leaves the scale, tritone does not"], a: 1, fb: "Tritone substitution specifically targets V7 (and secondary dominants). Diatonic substitution applies to any degree of the scale." },
  { q: "Which technique creates the most chromatic bass movement?", opts: ["Diatonic substitution","Modal borrowing","Tritone substitution","Whole-tone parallel harmonization"], a: 2, fb: "Tritone substitution creates the most direct chromatic bass motion: V7 → sub(V7) → I gives ½ tone → I (e.g., G → D♭ → C). It is the most expressive and most 'jazz'." },
  { q: "Which technique is the 'softest' (least chromatic, within the key)?", opts: ["Tritone substitution","Modal borrowing","Chromatic parallel harmonization","Diatonic substitution"], a: 3, fb: "Diatonic substitution stays entirely within the scale — it never leaves the key. It is the least chromatic technique, the most 'inside' the key." },
  { q: "Bill Evans was born and died in:", opts: ["1910–1975","1929–1980","1945–1990","1920–1965"], a: 1, fb: "Bill Evans (1929–1980) is one of the most influential jazz pianists of the 20th century. His harmonic innovations — reharmonizations, cluster voicings, modal borrowings — defined modern jazz piano." },
  { q: "Which Miles Davis album (featuring Bill Evans) is foundational for modal jazz?", opts: ["A Love Supreme","Kind of Blue (1959)","Bitches Brew","Sketches of Spain"], a: 1, fb: "Kind of Blue (1959) is the best-selling jazz album of all time. Bill Evans contributed the liner notes. So What, Flamenco Sketches — each illustrates a distinct modal approach." },
  { q: "Brad Mehldau is particularly known for his reharmonizations of:", opts: ["Bach and Handel only","Jazz standards and pop/rock songs (Radiohead, Beatles)","Film music","Italian operas"], a: 1, fb: "Brad Mehldau (born 1970) is famous for his jazz reinterpretations of pop and rock — Radiohead (Exit Music for a Film), Beatles (Blackbird). His reharmonizations transform these familiar melodies into sophisticated jazz works." },
  { q: "The 'Coltrane changes' progression (Giant Steps) uses what principle?", opts: ["Diatonic substitutions only","A cycle of major thirds dividing the octave into 3 equal parts","Parallel block harmonization","Modal borrowings from Phrygian mode"], a: 1, fb: "John Coltrane in Giant Steps (1960) divides the octave into three major thirds: B – G – E♭ – B. Each key lasts only 2 beats. This is a radical reharmonization that replaces the circle of fifths." },
  { q: "Which classical composer strongly influenced parallel jazz harmonization?", opts: ["Rachmaninov","Debussy (French impressionism)","Brahms","Bartók"], a: 1, fb: "Claude Debussy (1862–1918) directly influenced jazz through his parallel chords, whole-tone scales, and non-functional harmonic colors. Bill Evans cited Debussy as a major influence." },
  { q: "Which statement best describes reharmonization as a creative tool?", opts: ["It is a technique for correcting incorrect harmonies","It is the art of transforming the harmonic color of a work while respecting its melody — a personal signature","It is only a pedagogical technique","It is a simplification technique for beginners"], a: 1, fb: "Reharmonization is a personal musical signature. Bill Evans, Miles Davis, Keith Jarrett, Brad Mehldau — each developed a recognizable language. It is the art of transforming a work into personal expression, while respecting the melody." },
  { q: "To reharmonize a gospel I–IV–I–V progression, which technique would be idiomatic?", opts: ["Tritone substitutions on every chord","Modal borrowings (IVm, ♭VII) to add minor color in a major context","Chromatic parallel harmonization","Coltrane Changes"], a: 1, fb: "Gospel frequently uses modal borrowings — IVm (Fm in C), ♭VI, ♭VII — which introduce the blue color in a major context. The I – IVm – I – V progression is characteristic of gospel." },
  { q: "Which illustrates a double technique: modal borrowing + parallel harmonization?", opts: ["Dm7 → G7 → CMaj7","CMaj7 → Cm7 → Fm7 then Fm7 → EMaj7 → E♭Maj7","G7 → D♭7 → C","Am7 → Fmaj7 → G7"], a: 1, fb: "CMaj7 → Cm7 → Fm7: modal borrowing (C minor). Then Fm7 → EMaj7 → E♭Maj7: descending chromatic parallel harmonization. The combination creates a very 'Bill Evans' progression." },
];

const questionsEs: Question[] = [
  { q: "¿Qué es la rearmonización?", opts: ["Transponer una melodía a otra tonalidad","Reemplazar los acordes de una progresión conservando la melodía","Añadir extensiones a todos los acordes","Cambiar el ritmo armónico"], a: 1, fb: "La rearmonización consiste en reemplazar los acordes de una progresión existente por otros acordes, conservando la melodía intacta. Es el arte de cambiar 'el suelo' sin tocar 'el techo'." },
  { q: "¿Cuál es la restricción fundamental de la rearmonización?", opts: ["Los nuevos acordes deben estar en la misma tonalidad","La melodía debe permanecer compatible con los nuevos acordes","El ritmo armónico debe duplicarse","Los acordes deben ser más complejos"], a: 1, fb: "La melodía debe permanecer compatible con los nuevos acordes — esta es la restricción fundamental. La nota de melodía debe ser consonante con cada nuevo acorde (fundamental, tercera, quinta, 7ª, 9ª, 11ª, 13ª)." },
  { q: "¿Qué es un 'guide-tone'?", opts: ["La nota más alta del acorde","La tercera y la séptima de un acorde de dominante","La fundamental y la quinta","La 9ª de un acorde extendido"], a: 1, fb: "Los guide-tones son la tercera y la séptima de un acorde de dominante. Estas dos notas definen el tritono característico — están en el corazón de las sustituciones de tritono." },
  { q: "¿Qué compositor es famoso por sus rearmonizaciones impresionistas?", opts: ["Beethoven","Mozart","Bill Evans","Haendel"], a: 2, fb: "Bill Evans (1929–1980) es uno de los grandes maestros de la rearmonización. Sus rearmonizaciones de estándares de jazz, usando préstamos modales y armonización paralela, revolucionaron el piano de jazz." },
  { q: "¿Por qué rearmonizar?", opts: ["Para facilitar la lectura","Para corregir un error armónico","Para enriquecer el color, crear interés, personalizar el arreglo","Para acortar la progresión"], a: 2, fb: "Rearmonizamos para enriquecer el color armónico, crear interés o sorpresa, personalizar un arreglo, o expresar una visión musical diferente." },
  { q: "Una nota de melodía es 'compatible' con un acorde si:", opts: ["Es solo la fundamental del acorde","Es fundamental, 3ª, 5ª, 7ª, 9ª, #11 o 13ª del acorde","No está en el acorde","Es la nota más alta del acorde"], a: 1, fb: "Una nota es compatible si pertenece a las extensiones del acorde: fundamental, tercera, quinta, 7ª, 9ª, 11ª aumentada (#4), 13ª. Las notas de tensión fuerte (9ª menor, 11ª justa en acorde mayor) generalmente se evitan." },
  { q: "¿Cuál es la avoid note clásica en un acorde Maj7?", opts: ["La 9ª","La 4ª justa (11ª natural)","La 6ª mayor","La 7ª menor"], a: 1, fb: "La 4ª justa (11ª natural) es la avoid note clásica en un acorde Maj7. En CMaj7, Fa está a ½ tono de Mi (tercera del acorde) — disonancia muy fuerte. En jazz se prefiere Fa# (#11)." },
  { q: "¿Qué movimiento de bajo suele crear una buena rearmonización?", opts: ["Bajo estático","Bajo por saltos de octava","Bajo con movimiento cromático o por grado conjunto","Bajo por quintas"], a: 2, fb: "Una rearmonización eficaz crea a menudo un movimiento de bajo cromático o por grado conjunto — p.ej., Re → Re♭ → Do en la sustitución de tritono en Autumn Leaves. Este movimiento fluido es una firma de las mejores rearmonizaciones." },
  { q: "La rearmonización se usa especialmente en:", opts: ["La música barroca","La música serial","El jazz y la música impresionista","La polifonía medieval"], a: 2, fb: "La rearmonización es central en el jazz (Bill Evans, Miles Davis, Brad Mehldau) y la música impresionista (Debussy, Ravel). Estos estilos comparten el gusto por el color armónico en lugar de tensión-resolución." },
  { q: "En una rearmonización, ¿qué parámetro NO cambia por definición?", opts: ["Los acordes","La melodía","El ritmo armónico","La tonalidad general"], a: 1, fb: "Por definición, la rearmonización conserva la melodía intacta. Es el principio fundador: los acordes cambian 'bajo' la melodía, que permanece igual." },
  { q: "La noción de armonía 'funcional' vs armonía 'colorista' es central porque:", opts: ["Una es jazz y la otra clásica","La armonía funcional crea tensión-resolución, la colorista crea atmósferas","La colorista es solo modal","La funcional es solo diatónica"], a: 1, fb: "Armonía funcional: los acordes crean tensión–resolución. Armonía colorista: los acordes son colores autónomos. La rearmonización puede ir hacia más colorismo (Evans, Debussy) o permanecer funcional (bebop)." },
  { q: "¿Se puede rearmonizar modificando el ritmo armónico?", opts: ["No, el ritmo armónico no forma parte de la rearmonización","Sí — acelerar (más acordes) o ralentizar (pedales) también es una forma de rearmonización","Sí, pero solo acelerando","No, la melodía impide cualquier cambio de ritmo"], a: 1, fb: "El ritmo armónico (frecuencia de los cambios de acordes) puede modificarse en una rearmonización. Un pedal (acorde sostenido) o una subdivisión más densa son herramientas de rearmonización por derecho propio." },
  { q: "¿Puede una rearmonización modificar la tonalidad de una pieza?", opts: ["No, nunca","Sí — una rearmonización puede inducir una nueva tonalidad","Sí, pero solo hacia el relativo menor","Solo si también se cambia el modo"], a: 1, fb: "Sí — una rearmonización audaz puede deslizarse hacia una nueva tonalidad implícita. Es de hecho una manera de crear una modulación progresiva y fluida, sin ruptura brusca." },
  { q: "¿Qué estilo musical popularizó la rearmonización como técnica de arreglo codificada?", opts: ["La música clásica barroca","El jazz de los años 1950–1970","La música folk","La música contemporánea dodecafónica"], a: 1, fb: "El jazz de los años 1950–1970 — especialmente el jazz modal y post-bop — popularizó la rearmonización sistemática. Miles Davis, Bill Evans y sus contemporáneos elevaron esta técnica al rango de arte." },
  { q: "¿Cuál es la diferencia entre sustitución y rearmonización?", opts: ["Son sinónimos exactos","La sustitución reemplaza un acorde, la rearmonización transforma toda una progresión","La sustitución es más avanzada","La rearmonización no cambia la melodía"], a: 1, fb: "La sustitución designa el reemplazo de un acorde específico (p.ej., G7 → Re♭7). La rearmonización es un término más amplio que puede transformar toda una progresión — engloba la sustitución y otras técnicas." },
  { q: "¿Qué es la sustitución diatónica?", opts: ["Reemplazar un acorde por su acorde de dominante","Reemplazar un acorde por otro acorde diatónico que comparte notas comunes","Añadir la 7ª a todos los acordes","Reemplazar los acordes menores por mayores"], a: 1, fb: "La sustitución diatónica reemplaza un acorde por otro acorde de la misma escala (diatónico) que comparte notas comunes. Los acordes a distancia de tercera son los mejores candidatos — comparten 2 notas de 3." },
  { q: "¿Por qué los acordes a distancia de tercera son buenos sustitutos diatónicos?", opts: ["Tienen la misma fundamental","Comparten 2 notas comunes de 3 (tríada)","Son siempre de la misma calidad","Crean exactamente el mismo color"], a: 1, fb: "En Do mayor: DoMaj (C E G) y Mim (E G B) comparten Mi y Sol. Esta comunidad de notas garantiza que la melodía permanezca compatible — es el principio de la sustitución diatónica." },
  { q: "¿Qué acorde es el sustituto diatónico natural de I (acorde de tónica)?", opts: ["IV","V","VI (relativo menor)","VII"], a: 2, fb: "VIm (relativo menor) es el sustituto diatónico natural de I. En Do mayor: Lam sustituye a DoMaj — comparten Do y Mi, dos de las tres notas de la tríada." },
  { q: "En Do mayor, ¿qué acorde puede sustituir a Rem7 por sustitución diatónica?", opts: ["SolMaj7","FaMaj7","Sim7♭5","DoMaj7"], a: 1, fb: "FaMaj7 puede sustituir a Rem7 — comparten Fa, La, Do (3 notas comunes). FaMaj7 = F A C E; Rem7 = D F A C. Tres notas comunes: Fa, La, Do." },
  { q: "La progresión II–V–I (Rem7–Sol7–DoMaj7) rearmonizada como FaMaj7–Mim7–DoMaj7 ilustra:", opts: ["Sustitución de tritono","Sustitución diatónica de los dos primeros acordes","Préstamo modal","Armonización paralela"], a: 1, fb: "FaMaj7 sustituye a Rem7 (3 notas comunes: F A C), Mim7 sustituye a Sol7 (3 notas comunes: G B D). Doble sustitución diatónica — la tensión del II–V se difumina, el color se vuelve más modal." },
  { q: "En Sol mayor, ¿qué acorde es el sustituto diatónico natural de SolMaj7 (I)?", opts: ["Lam7 (II)","Sim7 (III)","Mim7 (VI)","Re7 (V)"], a: 2, fb: "Mim7 (VIm) es el sustituto diatónico natural de SolMaj7 (I) en Sol mayor. SolMaj7 = G B D F#; Mim7 = E G B D. Comparten Sol, Si, Re — tres notas comunes." },
  { q: "¿Qué riesgo principal conlleva la sustitución diatónica?", opts: ["Salir de la tonalidad","Perder la tensión armónica del original (el V7 pierde su función de dominante)","Hacer la progresión demasiado compleja","Crear movimientos de bajo paralelos"], a: 1, fb: "Al sustituir V7, se puede perder la tensión de dominante. Es un riesgo (menos tensión) pero también una ventaja (atmósfera más modal, menos tonal)." },
  { q: "Mim7 → Sol7 en Do mayor ilustra qué relación diatónica:", opts: ["Sustituto a distancia de 2ª","IIIm sustituye a V7 (comparten G, B, D)","Sustituto a distancia de quinta","Sustituto de subdominante"], a: 1, fb: "Mim7 y Sol7 comparten Sol, Si, Re — tres notas comunes. Mim7 puede sustituir a Sol7 creando un color menos tenso. Es la sustitución por el IIIm del Vº grado." },
  { q: "La sustitución diatónica siempre preserva:", opts: ["La calidad (mayor/menor) del acorde original","La función armónica del acorde original","La tonalidad general de la progresión","La nota de bajo original"], a: 2, fb: "La sustitución diatónica permanece en la misma escala — preserva la tonalidad general. Sin embargo, puede modificar la función y la calidad del acorde." },
  { q: "¿Qué es la sustitución de tritono?", opts: ["Reemplazar cualquier acorde por su transposición de tritono","Reemplazar V7 por el acorde de dominante situado un tritono más abajo","Añadir un tritono al acorde de dominante","Usar acordes aumentados"], a: 1, fb: "La sustitución de tritono reemplaza V7 por el acorde de dominante situado un tritono más abajo (6 semitonos). Sol7 → Re♭7. Estos dos acordes comparten sus guide-tones (tercera y séptima invertidas)." },
  { q: "¿Por qué Sol7 y Re♭7 son sustitutos de tritono el uno del otro?", opts: ["Tienen la misma fundamental una octava arriba","Comparten los mismos guide-tones: Si/Do♭ y Fa (enarmónicos)","Ambos están en modo dórico","Tienen la misma quinta"], a: 1, fb: "Sol7 guide-tones: Si (3ª) y Fa (7ª). Re♭7 guide-tones: Fa (3ª) y Do♭/Si (7ª). Si y Do♭ son enarmónicos, Fa es común. Estas dos notas de tensión son compartidas." },
  { q: "¿Cuál es el sustituto de tritono de Do7?", opts: ["Fa7","Sol♭7","Sol7","Mi♭7"], a: 1, fb: "Sol♭7 es el sustituto de tritono de Do7. Distancia Do → Sol♭ = 6 semitonos. Do7 guide-tones: Mi (3ª) y Si♭ (7ª); Sol♭7 guide-tones: Si♭ (3ª) y Fa♭/Mi (7ª)." },
  { q: "¿Qué efecto crea la sustitución de tritono sobre el bajo?", opts: ["Bajo que sube una quinta","Bajo cromático descendente (p.ej., Sol → Re♭ → Do)","Bajo estático","Bajo que desciende por quintas"], a: 1, fb: "La sustitución de tritono crea un bajo cromático descendente. En II–V–I en Do con sub tritónica en V: Re → Re♭ → Do. Este movimiento de ½ tono Re♭→Do es muy expresivo y fluido." },
  { q: "La sustitución de tritono se aplica principalmente a:", opts: ["Todos los tipos de acordes","Acordes de tónica (Maj7)","Acordes de dominante (7ª)","Acordes de subdominante menores"], a: 2, fb: "La sustitución de tritono se aplica principalmente a los acordes de dominante (7ª). El tritono interno del V7 (guide-tone) es la condición necesaria." },
  { q: "En Autumn Leaves en Dom, la sustitución de tritono de Sol7 da:", opts: ["Do7","Fa#7 / Sol♭7","Re♭7","La♭7"], a: 2, fb: "Sol7 → Re♭7 (tritono de Sol). El bajo se convierte en: Rem7♭5 (Re) → Re♭7 (Re♭) → Dom (Do) — movimiento cromático Re → Re♭ → Do. Es una de las rearmonizaciones más célebres del jazz." },
  { q: "La sustitución de tritono se desarrolló principalmente en:", opts: ["La música barroca (siglo XVII)","El jazz bebop (años 1940–1950)","La música serial (siglo XX)","El impresionismo (principios del siglo XX)"], a: 1, fb: "La sustitución de tritono se desarrolló en el bebop de los años 1940–1950, popularizada por Charlie Parker, Dizzy Gillespie y Thelonious Monk." },
  { q: "¿Cuál es el sustituto de tritono de Re7?", opts: ["Sol#7 / La♭7","La7","Mi♭7 / Re♯7","Fa7"], a: 0, fb: "La♭7 es el sustituto de tritono de Re7. Distancia Re → La♭ = 6 semitonos. Re7 guide-tones: Fa# (3ª) y Do (7ª). La♭7 guide-tones: Do (3ª) y Sol♭ (7ª = Fa# enarmónico)." },
  { q: "¿Cuál es el sustituto de tritono de Fa7?", opts: ["Si7","Do7","Mi7","Sol7"], a: 0, fb: "Si7 es el sustituto de tritono de Fa7. Distancia Fa → Si = 6 semitonos. Fa7 guide-tones: La (3ª) y Mi♭ (7ª). Si7 guide-tones: Re# (3ª = Mi♭ enarmónico) y La (7ª)." },
  { q: "¿Se puede aplicar la sustitución de tritono a una dominante secundaria?", opts: ["No, solo al V7 principal","Sí — el V7/II (La7 en Do) puede reemplazarse por Mi♭7","Sí, pero solo si es el V7/IV","Solo si la progresión dura al menos 2 compases"], a: 1, fb: "Sí — la sustitución de tritono se aplica a cualquier acorde de dominante, incluidas las dominantes secundarias. V7/II = La7 en Do mayor → Mi♭7 (tritono de La)." },
  { q: "¿Qué es un préstamo modal?", opts: ["Usar escalas modales en una progresión tonal","Tomar prestado un acorde del modo paralelo (misma tónica, modo diferente)","Transponer un acorde a otro modo","Usar el modo lidio en un acorde mayor"], a: 1, fb: "El préstamo modal consiste en tomar prestado un acorde del modo paralelo — misma tónica, modo diferente. En Do mayor, Fam7 es prestado de Do menor. La tónica es la misma, se toma el color del menor." },
  { q: "En Do mayor, ¿qué acordes se toman típicamente prestados del modo menor paralelo?", opts: ["Lam7, Mim7, Rem7","♭VIMaj7, ♭VIIMaj7, IVm7","II7, III7, VI7","VIIdim, IVdim, IIdim"], a: 1, fb: "Préstamos clásicos del menor paralelo en Do mayor: Fam7 (IVm), La♭Maj7 (♭VI), Si♭Maj7 (♭VII). Estos acordes con bemoles introducen ♭ ajenos a Do mayor pero naturales en Do menor." },
  { q: "El acorde ♭VIIMaj7 en Do mayor (Si♭Maj7) está prestado de:", opts: ["Sol mixolidio","Do menor (eólico)","Fa lidio","Re dórico"], a: 1, fb: "Si♭Maj7 = ♭VIIMaj7 en Do mayor. En Do menor natural (eólico), el VIIº grado es Si♭ — es el acorde ♭VII natural del menor, prestado del modo menor paralelo." },
  { q: "La sucesión DoMaj7 → Dom7 ilustra:", opts: ["Sustitución de tritono","Préstamo modal (misma tónica, color mayor → menor)","Armonización paralela","Sustitución diatónica"], a: 1, fb: "DoMaj7 → Dom7: misma fundamental Do, paso del modo mayor al menor. Este es el corazón del préstamo modal — misma tónica, color diferente. Bill Evans explota este gesto en Peace Piece." },
  { q: "Bill Evans usa el préstamo modal en Peace Piece:", opts: ["Reemplazando Sol7 por Re♭7","Tomando prestados Dom7 y Fam7 del modo Do menor sobre un pedal de Do","Usando escalas pentatónicas","Transponiendo la melodía al modo dórico"], a: 1, fb: "En Peace Piece, Evans mantiene Do como pedal de bajo y toma prestados Dom7 y Fam7 del Do menor paralelo. Esta oscilación Maj7 ↔ m7 crea el color meditativo característico de la pieza." },
  { q: "En Sol mayor, ¿qué acorde es el préstamo modal ♭VIMaj7?", opts: ["Mi♭Maj7","FaMaj7","Si♭Maj7","La♭Maj7"], a: 0, fb: "♭VI en Sol = Mi♭. Mi♭Maj7 está prestado de Sol menor (Sol eólico) donde el VIº grado es Mi♭. Es un acorde muy expresivo en una progresión en Sol mayor." },
  { q: "El acorde IVm en una tonalidad mayor (p.ej., Fam en Do) ¿qué efecto crea?", opts: ["Claridad y estabilidad reforzadas","Un color oscuro inesperado por la tercera menor y la 7ª bemolizada prestadas","Mayor tensión de dominante","Resolución plagal pura"], a: 1, fb: "Fam7 = F La♭ Do Mi♭. El La♭ y el Mi♭ están prestados de Do menor. Estas notas ♭ crean un color oscuro inesperado en un contexto mayor — es precisamente el efecto buscado." },
  { q: "¿Se pueden tomar prestados acordes de otros modos que no sean el menor paralelo?", opts: ["No, solo del menor paralelo","Sí — frigio, lidio, dórico, etc. también son fuentes de préstamos","Sí, pero solo en el jazz","Solo para los acordes de subdominante"], a: 1, fb: "Sí — se puede tomar prestado de cualquier modo paralelo. ♭II (de frigio), #IV (de lidio), ♭VI (de mixolidio o eólico), etc. Cuanto más lejano sea el modo, más sorprendente el color." },
  { q: "¿Qué es la armonización paralela?", opts: ["Armonizar una melodía con dos voces a la tercera","Transponer un bloque de acordes de la misma calidad por movimiento conjunto (semitonos o tonos)","Doblar la melodía a la octava inferior","Usar acordes paralelos a distancia de quinta"], a: 1, fb: "La armonización paralela consiste en transponer un bloque de acordes (de la misma calidad) por movimiento conjunto. DoMaj7 → SiMaj7 → Si♭Maj7: tres Maj7 descendiendo cromáticamente." },
  { q: "El paralelismo cromático con acordes Maj7 está asociado a:", opts: ["El contrapunto barroco estricto","El impresionismo francés y el jazz modal (Debussy, Bill Evans)","La música serial","El blues tradicional"], a: 1, fb: "El paralelismo cromático con Maj7 es la firma del impresionismo (Debussy) y el jazz modal (Bill Evans, Herbie Hancock). Es uno de los sonidos más 'contemporáneos' en armonía." },
  { q: "En una armonización paralela, la melodía:", opts: ["Debe moverse necesariamente por grado conjunto","Puede permanecer en una nota sostenida mientras los acordes se mueven","Debe seguir la misma dirección que los acordes","Debe doblarse a la tercera inferior"], a: 1, fb: "La nota de melodía puede permanecer sostenida (pedal melódico) mientras los acordes descienden cromáticamente. Esta tensión entre melodía fija y armonía móvil es muy expresiva." },
  { q: "DoMaj7 → SiMaj7 → Si♭Maj7 ilustra una armonización paralela:", opts: ["Por tonos enteros","Cromática descendente (½ tono ½ tono)","Por terceras descendentes","Por quintas descendentes"], a: 1, fb: "Do → Si → Si♭: cada fundamental desciende un semitono. Es el paralelismo cromático — el más expresivo en el jazz moderno." },
  { q: "¿Qué compositor clásico popularizó los acordes en deslizamiento paralelo?", opts: ["Debussy","Beethoven","Brahms","Schoenberg"], a: 0, fb: "Claude Debussy popularizó los acordes en deslizamiento paralelo en el impresionismo. En 'La catedral sumergida', bloques paralelos crean el característico color de órgano." },
  { q: "¿Por qué la armonización paralela 'libera' a los acordes de sus funciones tonales?", opts: ["Elimina los acordes de dominante","Los acordes paralelos crean un color, no una tensión-resolución — pensamiento colorista","Cambia la tonalidad en cada acorde","Usa solo acordes de subdominante"], a: 1, fb: "En el paralelismo, los acordes ya no desempeñan su rol funcional (T/SD/D) — cada acorde es un color en sí mismo. Es el pensamiento modal/colorista en lugar del funcional/tonal." },
  { q: "Comparar sustitución diatónica y tritónica: ¿qué afirmación es verdadera?", opts: ["La diatónica se aplica a V7, la tritónica a todos los acordes","La sustitución tritónica se aplica específicamente a V7; la diatónica se aplica a todos los grados","Ambas se aplican solo a acordes menores","La diatónica sale de la escala, la tritónica no"], a: 1, fb: "La sustitución tritónica apunta específicamente a V7 (y las dominantes secundarias). La sustitución diatónica se aplica a cualquier grado de la escala." },
  { q: "¿Qué técnica crea el movimiento de bajo más cromático?", opts: ["Sustitución diatónica","Préstamo modal","Sustitución de tritono","Armonización paralela por tonos"], a: 2, fb: "La sustitución de tritono crea el movimiento de bajo cromático más directo: V7 → sub(V7) → I da ½ tono → I (p.ej., Sol → Re♭ → Do). Es el más expresivo y el más 'jazz'." },
  { q: "¿Qué técnica es la más 'suave' (menos cromática, dentro de la tonalidad)?", opts: ["Sustitución de tritono","Préstamo modal","Armonización paralela cromática","Sustitución diatónica"], a: 3, fb: "La sustitución diatónica permanece completamente dentro de la escala — nunca sale de la tonalidad. Es la técnica menos cromática, la más 'interior' a la tonalidad." },
  { q: "Bill Evans nació y murió en:", opts: ["1910–1975","1929–1980","1945–1990","1920–1965"], a: 1, fb: "Bill Evans (1929–1980) es uno de los pianistas de jazz más influyentes del siglo XX. Sus innovaciones armónicas — rearmonizaciones, voicings en clusters, préstamos modales — definieron el piano de jazz moderno." },
  { q: "¿Qué álbum de Miles Davis (con Bill Evans) es fundacional para el jazz modal?", opts: ["A Love Supreme","Kind of Blue (1959)","Bitches Brew","Sketches of Spain"], a: 1, fb: "Kind of Blue (1959) es el álbum de jazz más vendido de todos los tiempos. Bill Evans contribuyó con las notas de programa. So What, Flamenco Sketches — cada uno ilustra un enfoque modal distinto." },
  { q: "Brad Mehldau es especialmente conocido por sus rearmonizaciones de:", opts: ["Bach y Haendel únicamente","Estándares de jazz y canciones pop/rock (Radiohead, Beatles)","Música de cine","Óperas italianas"], a: 1, fb: "Brad Mehldau (nacido en 1970) es famoso por sus reinterpretaciones jazz de pop y rock — Radiohead (Exit Music for a Film), Beatles (Blackbird). Sus rearmonizaciones transforman estas melodías conocidas en obras de jazz sofisticadas." },
  { q: "La progresión 'Coltrane changes' (Giant Steps) utiliza qué principio:", opts: ["Solo sustituciones diatónicas","Un ciclo de terceras mayores que divide la octava en 3 partes iguales","Armonización paralela en bloques","Préstamos modales del modo frigio"], a: 1, fb: "John Coltrane en Giant Steps (1960) divide la octava en tres terceras mayores: Si – Sol – Mi♭ – Si. Cada tonalidad dura solo 2 tiempos. Es una rearmonización radical que reemplaza el ciclo de quintas." },
  { q: "¿Qué pianista clásico influyó fuertemente en la armonización paralela del jazz?", opts: ["Rachmaninov","Debussy (impresionismo francés)","Brahms","Bartók"], a: 1, fb: "Claude Debussy (1862–1918) influyó directamente en el jazz a través de sus acordes paralelos, escalas por tonos y colores armónicos no funcionales. Bill Evans citaba a Debussy como influencia mayor." },
  { q: "¿Qué afirmación describe mejor la rearmonización como herramienta creativa?", opts: ["Es una técnica de corrección de armonías incorrectas","Es el arte de transformar el color armónico de una obra respetando su melodía — una firma personal","Es solo una técnica pedagógica","Es una técnica de simplificación para principiantes"], a: 1, fb: "La rearmonización es una firma musical personal. Bill Evans, Miles Davis, Keith Jarrett, Brad Mehldau — cada uno desarrolló un lenguaje reconocible. Es el arte de transformar una obra en expresión personal, respetando la melodía." },
  { q: "Para rearmonizar una progresión gospel I–IV–I–V, ¿qué técnica sería idiomática?", opts: ["Sustituciones de tritono en cada acorde","Préstamos modales (IVm, ♭VII) para añadir color menor en un contexto mayor","Armonización paralela cromática","Coltrane Changes"], a: 1, fb: "El gospel usa frecuentemente los préstamos modales — IVm (Fam en Do), ♭VI, ♭VII — que introducen el color 'blue' en un contexto mayor. La progresión I – IVm – I – V es característica del gospel." },
  { q: "¿Cuál ilustra una doble técnica: préstamo modal + armonización paralela?", opts: ["Rem7 → Sol7 → DoMaj7","DoMaj7 → Dom7 → Fam7 luego Fam7 → MiMaj7 → Mi♭Maj7","Sol7 → Re♭7 → Do","Lam7 → FaMaj7 → Sol7"], a: 1, fb: "DoMaj7 → Dom7 → Fam7: préstamo modal (Do menor). Luego Fam7 → MiMaj7 → Mi♭Maj7: armonización paralela cromática descendente. La combinación crea una progresión muy 'Bill Evans'." },
];

const questionsDe: Question[] = [
  { q: "Was ist Reharmonisierung?", opts: ["Eine Melodie in eine andere Tonart transponieren","Die Akkorde einer Progression ersetzen, während die Melodie erhalten bleibt","Erweiterungen zu allen Akkorden hinzufügen","Den harmonischen Rhythmus ändern"], a: 1, fb: "Reharmonisierung bedeutet, die Akkorde einer bestehenden Progression durch andere Akkorde zu ersetzen, während die Melodie unverändert bleibt. Es ist die Kunst, den 'Boden' zu verändern, ohne das 'Dach' anzutasten." },
  { q: "Was ist die grundlegende Einschränkung der Reharmonisierung?", opts: ["Die neuen Akkorde müssen in der gleichen Tonart sein","Die Melodie muss mit den neuen Akkorden kompatibel bleiben","Der harmonische Rhythmus muss sich verdoppeln","Die Akkorde müssen komplexer sein"], a: 1, fb: "Die Melodie muss mit den neuen Akkorden kompatibel bleiben — das ist die grundlegende Einschränkung. Die Melodienote muss konsonant mit jedem neuen Akkord sein (Grundton, Terz, Quinte, 7., 9., 11., 13.)." },
  { q: "Was ist ein 'Guide-Tone'?", opts: ["Die höchste Note des Akkords","Die Terz und Septime eines Dominantakkords","Grundton und Quinte","Die 9. eines erweiterten Akkords"], a: 1, fb: "Guide-Tones sind die Terz und Septime eines Dominantakkords. Diese beiden Noten definieren den charakteristischen Tritonus — sie sind das Herzstück der Tritonussubstitutionen." },
  { q: "Welcher Komponist ist für seine impressionistischen Reharmonisierungen bekannt?", opts: ["Beethoven","Mozart","Bill Evans","Händel"], a: 2, fb: "Bill Evans (1929–1980) ist einer der größten Meister der Reharmonisierung. Seine Reharmonisierungen von Jazzstandards, unter Verwendung modaler Anleihen und Parallelharmonisierung, revolutionierten das Jazzklavier." },
  { q: "Warum reharmonisieren?", opts: ["Um das Lesen zu erleichtern","Um einen harmonischen Fehler zu korrigieren","Um die Farbe zu bereichern, Interesse zu wecken, das Arrangement zu personalisieren","Um die Progression zu verkürzen"], a: 2, fb: "Wir reharmonisieren, um die harmonische Farbe zu bereichern, Interesse oder Überraschung zu erzeugen, ein Arrangement zu personalisieren oder eine andere musikalische Vision auszudrücken." },
  { q: "Eine Melodienote ist mit einem Akkord 'kompatibel', wenn:", opts: ["Sie nur der Grundton des Akkords ist","Sie Grundton, Terz, Quinte, 7., 9., #11 oder 13. des Akkords ist","Sie nicht im Akkord vorkommt","Sie die höchste Note des Akkords ist"], a: 1, fb: "Eine Note ist kompatibel, wenn sie zu den Erweiterungen des Akkords gehört: Grundton, Terz, Quinte, 7., 9., erhöhte 11. (#4), 13. Starke Spannungsnoten (kleine 9., reine 11. bei Durakkord) sind generell zu vermeiden." },
  { q: "Was ist die klassische Avoid Note bei einem Maj7-Akkord?", opts: ["Die 9.","Die reine Quarte (natürliche 11.)","Die große Sexte","Die kleine Septime"], a: 1, fb: "Die reine Quarte (natürliche 11.) ist die klassische Avoid Note bei einem Maj7-Akkord. In CMaj7 liegt F einen Halbton von E (Terz des Akkords) entfernt — sehr starke Halbton-Dissonanz. Im Jazz wird F# (#11) bevorzugt." },
  { q: "Welche Bassbewegung erzeugt eine gute Reharmonisierung oft?", opts: ["Statischer Bass","Bass in Oktavsprüngen","Bass mit chromatischer oder schrittweiser Bewegung","Bass in Quinten"], a: 2, fb: "Eine wirksame Reharmonisierung erzeugt oft chromatische oder schrittweise Bassbewegung — z.B. D → D♭ → C bei der Tritonussubstitution in Autumn Leaves. Diese fließende Bewegung ist ein Merkmal der besten Reharmonisierungen." },
  { q: "Reharmonisierung wird besonders verwendet in:", opts: ["Barockmusik","Serieller Musik","Jazz und impressionistischer Musik","Mittelalterlicher Polyphonie"], a: 2, fb: "Reharmonisierung ist zentral im Jazz (Bill Evans, Miles Davis, Brad Mehldau) und in der impressionistischen Musik (Debussy, Ravel). Diese Stile teilen eine Vorliebe für harmonische Farbe statt Spannung-Auflösung." },
  { q: "Welcher Parameter ändert sich bei einer Reharmonisierung per Definition NICHT?", opts: ["Die Akkorde","Die Melodie","Der harmonische Rhythmus","Die Gesamttonart"], a: 1, fb: "Per Definition bewahrt die Reharmonisierung die Melodie unverändert. Das ist das Gründungsprinzip: Die Akkorde ändern sich 'unter' der Melodie, die gleich bleibt." },
  { q: "Der Begriff 'funktionale' vs 'koloristische' Harmonik ist zentral, weil:", opts: ["Die eine Jazz und die andere klassisch ist","Funktionale Harmonisierung erzeugt Spannung-Auflösung, koloristische schafft Atmosphären","Koloristische ist nur modal","Funktionale ist nur diatonisch"], a: 1, fb: "Funktionale Harmonik: Akkorde erzeugen Spannung–Auflösung. Koloristische Harmonik: Akkorde sind autonome Farben. Reharmonisierung kann zu mehr Kolorismus (Evans, Debussy) oder funktional (Bebop) bleiben." },
  { q: "Kann man durch Änderung des harmonischen Rhythmus reharmonisieren?", opts: ["Nein, der harmonische Rhythmus gehört nicht zur Reharmonisierung","Ja — Beschleunigung (mehr Akkorde) oder Verlangsamung (Pedale) ist auch eine Form der Reharmonisierung","Ja, aber nur durch Beschleunigung","Nein, die Melodie verhindert jede Rhythmusänderung"], a: 1, fb: "Der harmonische Rhythmus (Häufigkeit der Akkordwechsel) kann in einer Reharmonisierung verändert werden. Ein Orgelpunkt (gehaltener Akkord) oder dichtere Unterteilungen sind vollwertige Reharmonisierungswerkzeuge." },
  { q: "Kann eine Reharmonisierung die Tonart eines Stückes ändern?", opts: ["Nein, niemals","Ja — eine Reharmonisierung kann eine neue Tonart einleiten","Ja, aber nur zur parallelen Moll-Tonart","Nur wenn auch der Modus geändert wird"], a: 1, fb: "Ja — eine kühne Reharmonisierung kann zu einer neuen impliziten Tonart gleiten. Dies ist tatsächlich eine Möglichkeit, eine schrittweise und fließende Modulation ohne brutalen Bruch zu erzeugen." },
  { q: "Welcher Musikstil hat die Reharmonisierung als kodifizierte Arrangementtechnik popularisiert?", opts: ["Barocke klassische Musik","Jazz der 1950er–1970er Jahre","Folkmusik","Zeitgenössische Zwölftonmusik"], a: 1, fb: "Jazz der 1950er–1970er Jahre — insbesondere modaler und Post-Bop-Jazz — popularisierte die systematische Reharmonisierung. Miles Davis, Bill Evans und ihre Zeitgenossen erhoben diese Technik zur Kunst." },
  { q: "Was ist der Unterschied zwischen Substitution und Reharmonisierung?", opts: ["Sie sind genaue Synonyme","Substitution ersetzt einen Akkord, Reharmonisierung transformiert eine ganze Progression","Substitution ist fortgeschrittener","Reharmonisierung ändert die Melodie nicht"], a: 1, fb: "Substitution bezeichnet den Ersatz eines bestimmten Akkords (z.B. G7 → D♭7). Reharmonisierung ist ein weiterer Begriff, der eine ganze Progression transformieren kann — er umfasst Substitution und andere Techniken." },
  { q: "Was ist diatonische Substitution?", opts: ["Einen Akkord durch seinen Dominantakkord ersetzen","Einen Akkord durch einen anderen diatonischen Akkord mit gemeinsamen Noten ersetzen","Allen Akkorden eine Septime hinzufügen","Mollakkorde durch Durakkorde ersetzen"], a: 1, fb: "Diatonische Substitution ersetzt einen Akkord durch einen anderen Akkord aus derselben Tonleiter (diatonisch), der gemeinsame Noten hat. Akkorde im Terzabstand sind die besten Kandidaten — sie teilen 2 von 3 Noten." },
  { q: "Warum sind Akkorde im Terzabstand gute diatonische Substitute?", opts: ["Sie haben denselben Grundton","Sie teilen 2 gemeinsame Noten von 3 (Dreiklang)","Sie sind immer von gleicher Qualität","Sie erzeugen genau die gleiche Farbe"], a: 1, fb: "In C-Dur: CMaj (C E G) und Em (E G B) teilen E und G. Diese Notengemeinschaft garantiert, dass die Melodie kompatibel bleibt — das ist das Prinzip der diatonischen Substitution." },
  { q: "Welcher Akkord ist das natürliche diatonische Substitut für I (Tonika-Akkord)?", opts: ["IV","V","VI (parallele Moll)","VII"], a: 2, fb: "VIm (parallele Moll) ist das natürliche diatonische Substitut für I. In C-Dur: Am substituiert CMaj — sie teilen C und E, zwei der drei Noten des Dreiklangs." },
  { q: "In C-Dur, welcher Akkord kann Dm7 durch diatonische Substitution ersetzen?", opts: ["GMaj7","Fmaj7","Bm7♭5","CMaj7"], a: 1, fb: "Fmaj7 kann Dm7 substituieren — sie teilen F, A, C (3 gemeinsame Noten). Fmaj7 = F A C E; Dm7 = D F A C. Drei gemeinsame Noten: F, A, C." },
  { q: "Die Progression II–V–I (Dm7–G7–CMaj7) reharmonisiert als Fmaj7–Em7–CMaj7 illustriert:", opts: ["Tritonussubstitution","Diatonische Substitution der ersten beiden Akkorde","Modale Anleihe","Parallelharmonisierung"], a: 1, fb: "Fmaj7 substituiert Dm7 (3 gemeinsame Noten: F A C), Em7 substituiert G7 (3 gemeinsame Noten: G B D). Doppelte diatonische Substitution — die II–V-Spannung wird aufgelöst, die Farbe wird modaler." },
  { q: "In G-Dur, welcher Akkord ist das natürliche diatonische Substitut für GMaj7 (I)?", opts: ["Am7 (II)","Bm7 (III)","Em7 (VI)","D7 (V)"], a: 2, fb: "Em7 (VIm) ist das natürliche diatonische Substitut für GMaj7 (I) in G-Dur. GMaj7 = G H D F#; Em7 = E G H D. Sie teilen G, H, D — drei gemeinsame Noten." },
  { q: "Was ist das Hauptrisiko der diatonischen Substitution?", opts: ["Die Tonart zu verlassen","Die harmonische Spannung des Originals zu verlieren (V7 verliert seine Dominantfunktion)","Die Progression zu komplex zu machen","Parallele Bassbewegungen zu erzeugen"], a: 1, fb: "Durch die Substitution von V7 kann die Dominantspannung verloren gehen. Dies ist ein Risiko (weniger Spannung), aber auch ein Vorteil (modalere, weniger tonale Atmosphäre)." },
  { q: "Em7 → G7 in C-Dur illustriert welche diatonische Beziehung?", opts: ["Substitut im Sekundabstand","IIIm substituiert V7 (teilen G, H, D)","Substitut im Quintabstand","Subdominant-Substitut"], a: 1, fb: "Em7 und G7 teilen G, H, D — drei gemeinsame Noten. Em7 kann G7 substituieren und erzeugt eine weniger gespannte Farbe. Dies ist die Substitution durch IIIm für den V. Grad." },
  { q: "Diatonische Substitution bewahrt immer:", opts: ["Die Qualität (Dur/Moll) des Originalakkords","Die harmonische Funktion des Originalakkords","Die Gesamttonart der Progression","Die ursprüngliche Bassnote"], a: 2, fb: "Diatonische Substitution bleibt in derselben Tonleiter — sie bewahrt die Gesamttonart. Sie kann jedoch die Funktion und Qualität des Akkords verändern." },
  { q: "Was ist Tritonussubstitution?", opts: ["Jeden Akkord durch seine Tritonustransposition ersetzen","V7 durch den Dominantakkord einen Tritonus tiefer ersetzen","Einem Dominantakkord einen Tritonus hinzufügen","Übermäßige Akkorde verwenden"], a: 1, fb: "Tritonussubstitution ersetzt V7 durch den Dominantakkord einen Tritonus tiefer (6 Halbtöne). G7 → D♭7. Diese beiden Akkorde teilen ihre Guide-Tones (Terz und Septime vertauscht)." },
  { q: "Warum sind G7 und D♭7 füreinander Tritonussubstitute?", opts: ["Sie haben denselben Grundton eine Oktave höher","Sie teilen dieselben Guide-Tones: H/C♭ und F (enharmonisch)","Beide sind im dorischen Modus","Sie haben die gleiche Quinte"], a: 1, fb: "G7 Guide-Tones: H (Terz) und F (Septime). D♭7 Guide-Tones: F (Terz) und C♭/H (Septime). H und C♭ sind enharmonisch, F ist gemeinsam. Diese beiden Spannungsnoten werden geteilt." },
  { q: "Was ist das Tritonussubstitut von C7?", opts: ["F7","G♭7","G7","E♭7"], a: 1, fb: "G♭7 ist das Tritonussubstitut von C7. Abstand C → G♭ = 6 Halbtöne. C7 Guide-Tones: E (Terz) und B♭ (Septime); G♭7 Guide-Tones: B♭ (Terz) und F♭/E (Septime)." },
  { q: "Welchen Effekt erzeugt die Tritonussubstitution auf den Bass?", opts: ["Bass, der eine Quinte aufsteigt","Absteigender chromatischer Bass (z.B. G → D♭ → C)","Statischer Bass","Bass, der in Quinten absteigt"], a: 1, fb: "Tritonussubstitution erzeugt einen absteigenden chromatischen Bass. In II–V–I in C mit Tritonussub auf V: D → D♭ → C. Diese Halbtonbewegung D♭→C ist sehr ausdrucksstark und fließend." },
  { q: "Tritonussubstitution wird hauptsächlich angewendet auf:", opts: ["Alle Akkordtypen","Tonika-Akkorde (Maj7)","Dominantakkorde (Septakkorde)","Moll-Subdominantakkorde"], a: 2, fb: "Tritonussubstitution wird hauptsächlich auf Dominantakkorde (Septakkorde) angewendet. Der interne Tritonus von V7 (Guide-Tone) ist die notwendige Voraussetzung." },
  { q: "In Autumn Leaves in c-Moll ergibt die Tritonussubstitution von G7:", opts: ["C7","F#7 / G♭7","D♭7","A♭7"], a: 2, fb: "G7 → D♭7 (Tritonus von G). Der Bass wird: Dm7♭5 (D) → D♭7 (D♭) → Cm (C) — chromatische Bewegung D → D♭ → C. Dies ist eine der berühmtesten Reharmonisierungen im Jazz." },
  { q: "Tritonussubstitution wurde hauptsächlich entwickelt in:", opts: ["Barockmusik (17. Jahrhundert)","Bebop-Jazz (1940er–1950er Jahre)","Serieller Musik (20. Jahrhundert)","Impressionismus (frühes 20. Jahrhundert)"], a: 1, fb: "Tritonussubstitution wurde im Bebop der 1940er–1950er Jahre entwickelt, popularisiert durch Charlie Parker, Dizzy Gillespie und Thelonious Monk." },
  { q: "Was ist das Tritonussubstitut von D7?", opts: ["G#7 / A♭7","A7","E♭7 / D♯7","F7"], a: 0, fb: "A♭7 ist das Tritonussubstitut von D7. Abstand D → A♭ = 6 Halbtöne. D7 Guide-Tones: F# (Terz) und C (Septime). A♭7 Guide-Tones: C (Terz) und G♭ (Septime = F# enharmonisch)." },
  { q: "Was ist das Tritonussubstitut von F7?", opts: ["H7","C7","E7","G7"], a: 0, fb: "H7 ist das Tritonussubstitut von F7. Abstand F → H = 6 Halbtöne. F7 Guide-Tones: A (Terz) und E♭ (Septime). H7 Guide-Tones: D# (Terz = E♭ enharmonisch) und A (Septime)." },
  { q: "Kann Tritonussubstitution auf eine Sekundärdominante angewendet werden?", opts: ["Nein, nur auf das Haupt-V7","Ja — V7/II (A7 in C) kann durch E♭7 ersetzt werden","Ja, aber nur wenn es V7/IV ist","Nur wenn die Progression mindestens 2 Takte dauert"], a: 1, fb: "Ja — Tritonussubstitution gilt für jeden Dominantakkord, einschließlich Sekundärdominanten. V7/II = A7 in C-Dur → E♭7 (Tritonus von A)." },
  { q: "Was ist eine modale Anleihe?", opts: ["Modale Tonleitern in einer tonalen Progression verwenden","Einen Akkord vom parallelen Modus ausleihen (gleiche Tonika, verschiedener Modus)","Einen Akkord in einen anderen Modus transponieren","Den Lydischen Modus auf einem Durakkord verwenden"], a: 1, fb: "Modale Anleihe bedeutet, einen Akkord vom parallelen Modus auszuleihen — gleiche Tonika, verschiedener Modus. In C-Dur ist Fm7 aus c-Moll ausgeliehen. Die Tonika bleibt gleich; die Farbe des Molls wird ausgeliehen." },
  { q: "In C-Dur, welche Akkorde werden typischerweise vom parallelen Moll-Modus ausgeliehen?", opts: ["Am7, Em7, Dm7","♭VIMaj7, ♭VIIMaj7, IVm7","II7, III7, VI7","VIIdim, IVdim, IIdim"], a: 1, fb: "Klassische Anleihen vom parallelen Moll in C-Dur: Fm7 (IVm), A♭Maj7 (♭VI), B♭Maj7 (♭VII). Diese erniedrigten Akkorde führen ♭-Vorzeichen ein, die C-Dur fremd, aber in c-Moll natürlich sind." },
  { q: "Der Akkord ♭VIIMaj7 in C-Dur (B♭Maj7) ist ausgeliehen aus:", opts: ["G-Mixolydisch","c-Moll (Äolisch)","F-Lydisch","D-Dorisch"], a: 1, fb: "B♭Maj7 = ♭VIIMaj7 in C-Dur. In c-natürlich-Moll (Äolisch) ist die VII. Stufe H♭ — das ist der natürliche ♭VII-Akkord des Molls, ausgeliehen vom parallelen Moll-Modus." },
  { q: "Die Folge CMaj7 → Cm7 illustriert:", opts: ["Tritonussubstitution","Modale Anleihe (gleiche Tonika, Dur → Moll-Farbe)","Parallelharmonisierung","Diatonische Substitution"], a: 1, fb: "CMaj7 → Cm7: gleicher Grundton C, Wechsel vom Dur- zum Moll-Modus. Das ist der Kern der modalen Anleihe — gleiche Tonika, verschiedene Farbe. Bill Evans nutzt diese Geste in Peace Piece." },
  { q: "Bill Evans verwendet modale Anleihe in Peace Piece, indem er:", opts: ["G7 durch D♭7 ersetzt","Cm7 und Fm7 vom c-Moll-Modus auf einem C-Orgelpunkt ausleiht","Pentatonische Tonleitern verwendet","Die Melodie in den Dorischen Modus transponiert"], a: 1, fb: "In Peace Piece hält Evans C als Bassspezialpunkt und leiht Cm7 und Fm7 vom parallelen c-Moll aus. Diese Maj7 ↔ m7-Schwingung erzeugt die meditative Farbe, die charakteristisch für das Stück ist." },
  { q: "In G-Dur, welcher Akkord ist die modale Anleihe ♭VIMaj7?", opts: ["E♭Maj7","FMaj7","B♭Maj7","A♭Maj7"], a: 0, fb: "♭VI in G = E♭. E♭Maj7 ist aus g-Moll (G-Äolisch) ausgeliehen, wo die VI. Stufe E♭ ist. Es ist ein sehr ausdrucksstarker Akkord in einer G-Dur-Progression." },
  { q: "Der IVm-Akkord in einer Durtonart (z.B. Fm in C) erzeugt welchen Effekt?", opts: ["Verstärkte Klarheit und Stabilität","Eine unerwartete dunkle Farbe durch die ausgeliehene kleine Terz und erniedrigte Septime","Mehr Dominantspannung","Reine plagale Auflösung"], a: 1, fb: "Fm7 = F A♭ C E♭. A♭ und E♭ sind aus c-Moll ausgeliehen. Diese ♭-Noten erzeugen eine unerwartete dunkle Farbe in einem Dur-Kontext — genau das ist der beabsichtigte Effekt." },
  { q: "Können Akkorde auch aus anderen Modi als dem parallelen Moll ausgeliehen werden?", opts: ["Nein, nur aus dem parallelen Moll","Ja — Phrygisch, Lydisch, Dorisch usw. sind ebenfalls Quellen für Anleihen","Ja, aber nur im Jazz","Nur für Subdominantakkorde"], a: 1, fb: "Ja — man kann aus jedem parallelen Modus ausleihen. ♭II (aus Phrygisch), #IV (aus Lydisch), ♭VI (aus Mixolydisch oder Äolisch) usw. Je weiter der Modus entfernt ist, desto überraschender die Farbe." },
  { q: "Was ist Parallelharmonisierung?", opts: ["Eine Melodie mit zwei Stimmen in Terzen harmonisieren","Einen Akkordblock gleicher Qualität durch schrittweise Bewegung (Halbtöne oder Ganztöne) transponieren","Die Melodie eine Oktave tiefer verdoppeln","Parallele Akkorde im Quintabstand verwenden"], a: 1, fb: "Parallelharmonisierung bedeutet, einen Akkordblock (gleicher Qualität) durch schrittweise Bewegung zu transponieren. CMaj7 → BMaj7 → B♭Maj7: drei Maj7-Akkorde chromatisch absteigend." },
  { q: "Chromatischer Parallelismus mit Maj7-Akkorden ist assoziiert mit:", opts: ["Strengem barocken Kontrapunkt","Französischem Impressionismus und modalem Jazz (Debussy, Bill Evans)","Serieller Musik","Traditionellem Blues"], a: 1, fb: "Chromatischer Parallelismus mit Maj7-Akkorden ist die Signatur des Impressionismus (Debussy) und des modalen Jazz (Bill Evans, Herbie Hancock). Es ist einer der 'zeitgenössischsten' Klänge in der Harmonik." },
  { q: "In der Parallelharmonisierung kann die Melodie:", opts: ["Muss sich zwingend schrittweise bewegen","Auf einer gehaltenen Note verweilen, während die Akkorde sich bewegen","Muss der gleichen Richtung wie die Akkorde folgen","Muss in der unteren Terz verdoppelt werden"], a: 1, fb: "Die Melodienote kann gehalten bleiben (melodischer Orgelpunkt), während die Akkorde chromatisch absteigen. Diese Spannung zwischen fixer Melodie und bewegter Harmonie ist sehr ausdrucksstark." },
  { q: "CMaj7 → BMaj7 → B♭Maj7 illustriert eine Parallelharmonisierung:", opts: ["In Ganztönen","Chromatisch absteigend (½ Ton ½ Ton)","In absteigenden Terzen","In absteigenden Quinten"], a: 1, fb: "C → H → B♭: jeder Grundton steigt um einen Halbton ab. Das ist chromatischer Parallelismus — der ausdrucksstärkste im modernen Jazz." },
  { q: "Welcher klassische Komponist popularisierte gleitende Parallelakkorde?", opts: ["Debussy","Beethoven","Brahms","Schönberg"], a: 0, fb: "Claude Debussy popularisierte gleitende Parallelakkorde im Impressionismus. In 'La cathédrale engloutie' erzeugen Parallelblöcke die charakteristische Orgelfarbe." },
  { q: "Warum 'befreit' Parallelharmonisierung Akkorde von ihren tonalen Funktionen?", opts: ["Sie eliminiert Dominantakkorde","Parallelakkorde erzeugen Farbe, keine Spannung-Auflösung — koloristisches Denken","Sie wechselt die Tonart bei jedem Akkord","Sie verwendet nur Subdominantakkorde"], a: 1, fb: "Im Parallelismus spielen Akkorde keine funktionale Rolle mehr (T/SD/D) — jeder Akkord ist eine Farbe für sich. Das ist modales/koloristisches Denken statt funktionalem/tonalem Denken." },
  { q: "Diatonische und Tritonussubstitution vergleichen: welche Aussage stimmt?", opts: ["Diatonisch gilt für V7, Tritonus für alle Akkorde","Tritonussubstitution gilt speziell für V7; diatonische gilt für alle Skalengrade","Beide gelten nur für Mollakkorde","Diatonisch verlässt die Tonleiter, Tritonus nicht"], a: 1, fb: "Tritonussubstitution zielt speziell auf V7 (und Sekundärdominanten). Diatonische Substitution gilt für jeden Grad der Tonleiter." },
  { q: "Welche Technik erzeugt die chromatischste Bassbewegung?", opts: ["Diatonische Substitution","Modale Anleihe","Tritonussubstitution","Ganzton-Parallelharmonisierung"], a: 2, fb: "Tritonussubstitution erzeugt die direkteste chromatische Bassbewegung: V7 → sub(V7) → I ergibt ½ Ton → I (z.B. G → D♭ → C). Es ist die ausdrucksstärkste und 'jazzigste'." },
  { q: "Welche Technik ist die 'sanfteste' (am wenigsten chromatisch, innerhalb der Tonart)?", opts: ["Tritonussubstitution","Modale Anleihe","Chromatische Parallelharmonisierung","Diatonische Substitution"], a: 3, fb: "Diatonische Substitution bleibt vollständig in der Tonleiter — sie verlässt die Tonart nie. Es ist die am wenigsten chromatische Technik, die 'innerste' der Tonart." },
  { q: "Bill Evans wurde geboren und starb in:", opts: ["1910–1975","1929–1980","1945–1990","1920–1965"], a: 1, fb: "Bill Evans (1929–1980) ist einer der einflussreichsten Jazzpianisten des 20. Jahrhunderts. Seine harmonischen Innovationen — Reharmonisierungen, Cluster-Voicings, modale Anleihen — definierten das moderne Jazzklavier." },
  { q: "Welches Miles-Davis-Album (mit Bill Evans) ist grundlegend für den modalen Jazz?", opts: ["A Love Supreme","Kind of Blue (1959)","Bitches Brew","Sketches of Spain"], a: 1, fb: "Kind of Blue (1959) ist das meistverkaufte Jazzalbum aller Zeiten. Bill Evans schrieb die Liner Notes. So What, Flamenco Sketches — jeder illustriert einen anderen modalen Ansatz." },
  { q: "Brad Mehldau ist besonders bekannt für seine Reharmonisierungen von:", opts: ["Nur Bach und Händel","Jazzstandards und Pop/Rock-Songs (Radiohead, Beatles)","Filmmusik","Italienischen Opern"], a: 1, fb: "Brad Mehldau (geboren 1970) ist berühmt für seine Jazz-Reinterpretationen von Pop und Rock — Radiohead (Exit Music for a Film), Beatles (Blackbird). Seine Reharmonisierungen verwandeln diese bekannten Melodien in ausgefeilte Jazzwerke." },
  { q: "Die 'Coltrane Changes'-Progression (Giant Steps) verwendet welches Prinzip?", opts: ["Nur diatonische Substitutionen","Einen Zyklus großer Terzen, der die Oktave in 3 gleiche Teile teilt","Parallelblock-Harmonisierung","Modale Anleihen aus dem Phrygischen Modus"], a: 1, fb: "John Coltrane teilt in Giant Steps (1960) die Oktave in drei große Terzen: H – G – E♭ – H. Jede Tonart dauert nur 2 Zählzeiten. Das ist eine radikale Reharmonisierung, die den Quintenzirkel ersetzt." },
  { q: "Welcher klassische Pianist beeinflusste die parallele Jazzharmonisierung stark?", opts: ["Rachmaninow","Debussy (Französischer Impressionismus)","Brahms","Bartók"], a: 1, fb: "Claude Debussy (1862–1918) beeinflusste den Jazz direkt durch seine Parallelakkorde, Ganztonleitern und nicht-funktionalen Harmonikfarben. Bill Evans nannte Debussy als großen Einfluss." },
  { q: "Welche Aussage beschreibt Reharmonisierung als kreatives Werkzeug am besten?", opts: ["Sie ist eine Technik zur Korrektur falscher Harmonien","Sie ist die Kunst, die harmonische Farbe eines Werkes zu transformieren und dabei seine Melodie zu respektieren — eine persönliche Signatur","Sie ist nur eine pädagogische Technik","Sie ist eine Vereinfachungstechnik für Anfänger"], a: 1, fb: "Reharmonisierung ist eine persönliche musikalische Signatur. Bill Evans, Miles Davis, Keith Jarrett, Brad Mehldau — jeder entwickelte eine erkennbare Sprache. Es ist die Kunst, ein Werk in persönlichen Ausdruck zu verwandeln und dabei die Melodie zu respektieren." },
  { q: "Um eine Gospel-Progression I–IV–I–V zu reharmonisieren, welche Technik wäre idiomatisch?", opts: ["Tritonussubstitutionen auf jedem Akkord","Modale Anleihen (IVm, ♭VII), um Mollfarbe in einem Durkontext hinzuzufügen","Chromatische Parallelharmonisierung","Coltrane Changes"], a: 1, fb: "Gospel verwendet häufig modale Anleihen — IVm (Fm in C), ♭VI, ♭VII — die die Blues-Farbe in einem Durkontext einführen. Die Progression I – IVm – I – V ist charakteristisch für Gospel." },
  { q: "Welches illustriert eine Doppeltechnik: modale Anleihe + Parallelharmonisierung?", opts: ["Dm7 → G7 → CMaj7","CMaj7 → Cm7 → Fm7 dann Fm7 → EMaj7 → E♭Maj7","G7 → D♭7 → C","Am7 → Fmaj7 → G7"], a: 1, fb: "CMaj7 → Cm7 → Fm7: modale Anleihe (c-Moll). Dann Fm7 → EMaj7 → E♭Maj7: chromatisch absteigende Parallelharmonisierung. Die Kombination erzeugt eine sehr 'Bill Evans'-Progression." },
];

const questionsIt: Question[] = [
  { q: "Cos'è la riarmonizzazione?", opts: ["Trasporre una melodia in un'altra tonalità","Sostituire gli accordi di una progressione conservando la melodia","Aggiungere estensioni a tutti gli accordi","Cambiare il ritmo armonico"], a: 1, fb: "La riarmonizzazione consiste nel sostituire gli accordi di una progressione esistente con altri accordi, conservando intatta la melodia. È l'arte di cambiare 'il terreno' senza toccare 'il tetto'." },
  { q: "Qual è il vincolo fondamentale della riarmonizzazione?", opts: ["I nuovi accordi devono essere nella stessa tonalità","La melodia deve rimanere compatibile con i nuovi accordi","Il ritmo armonico deve raddoppiare","Gli accordi devono essere più complessi"], a: 1, fb: "La melodia deve rimanere compatibile con i nuovi accordi — questo è il vincolo fondamentale. La nota melodica deve essere consonante con ogni nuovo accordo (fondamentale, terza, quinta, 7ª, 9ª, 11ª, 13ª)." },
  { q: "Cos'è un 'guide-tone'?", opts: ["La nota più alta dell'accordo","La terza e la settima di un accordo di dominante","La fondamentale e la quinta","La 9ª di un accordo esteso"], a: 1, fb: "I guide-tones sono la terza e la settima di un accordo di dominante. Queste due note definiscono il tritono caratteristico — sono al cuore delle sostituzioni di tritono." },
  { q: "Quale compositore è famoso per le sue riarmonizzazioni impressioniste?", opts: ["Beethoven","Mozart","Bill Evans","Haendel"], a: 2, fb: "Bill Evans (1929–1980) è uno dei più grandi maestri della riarmonizzazione. Le sue riarmonizzazioni di standard jazz, usando prestiti modali e armonizzazione parallela, hanno rivoluzionato il pianoforte jazz." },
  { q: "Perché riarmonizzare?", opts: ["Per facilitare la lettura","Per correggere un errore armonico","Per arricchire il colore, creare interesse, personalizzare l'arrangiamento","Per accorciare la progressione"], a: 2, fb: "Riarmonizziamo per arricchire il colore armonico, creare interesse o sorpresa, personalizzare un arrangiamento, o esprimere una visione musicale diversa." },
  { q: "Una nota melodica è 'compatibile' con un accordo se:", opts: ["È solo la fondamentale dell'accordo","È fondamentale, 3ª, 5ª, 7ª, 9ª, #11 o 13ª dell'accordo","Non è nell'accordo","È la nota più alta dell'accordo"], a: 1, fb: "Una nota è compatibile se appartiene alle estensioni dell'accordo: fondamentale, terza, quinta, 7ª, 9ª, 11ª aumentata (#4), 13ª. Le note di tensione forte (9ª minore, 11ª giusta su accordo maggiore) sono generalmente da evitare." },
  { q: "Qual è la classica avoid note su un accordo Maj7?", opts: ["La 9ª","La 4ª giusta (11ª naturale)","La 6ª maggiore","La 7ª minore"], a: 1, fb: "La 4ª giusta (11ª naturale) è la classica avoid note su un accordo Maj7. In CMaj7, Fa dista mezzo tono da Mi (terza dell'accordo) — dissonanza di mezzo tono molto forte. In jazz si preferisce Fa# (#11)." },
  { q: "Quale movimento del basso crea spesso una buona riarmonizzazione?", opts: ["Basso statico","Basso per salti di ottava","Basso con movimento cromatico o per gradi congiunti","Basso per quinte"], a: 2, fb: "Una riarmonizzazione efficace crea spesso un movimento del basso cromatico o per gradi congiunti — es. Re → Re♭ → Do nella sostituzione di tritono su Autumn Leaves. Questo movimento fluido è una caratteristica delle migliori riarmonizzazioni." },
  { q: "La riarmonizzazione è particolarmente usata in:", opts: ["La musica barocca","La musica seriale","Il jazz e la musica impressionista","La polifonia medievale"], a: 2, fb: "La riarmonizzazione è centrale nel jazz (Bill Evans, Miles Davis, Brad Mehldau) e nella musica impressionista (Debussy, Ravel). Questi stili condividono il gusto per il colore armonico piuttosto che la tensione-risoluzione." },
  { q: "In una riarmonizzazione, quale parametro NON cambia per definizione?", opts: ["Gli accordi","La melodia","Il ritmo armonico","La tonalità generale"], a: 1, fb: "Per definizione, la riarmonizzazione conserva intatta la melodia. È il principio fondatore: gli accordi cambiano 'sotto' la melodia, che rimane la stessa." },
  { q: "La nozione di armonia 'funzionale' vs armonia 'coloristica' è centrale perché:", opts: ["Una è jazz e l'altra classica","L'armonizzazione funzionale crea tensione-risoluzione, quella coloristica crea atmosfere","La coloristica è solo modale","La funzionale è solo diatonica"], a: 1, fb: "Armonia funzionale: gli accordi creano tensione–risoluzione. Armonia coloristica: gli accordi sono colori autonomi. La riarmonizzazione può andare verso più colorismo (Evans, Debussy) o restare funzionale (bebop)." },
  { q: "Si può riarmonizzare modificando il ritmo armonico?", opts: ["No, il ritmo armonico non fa parte della riarmonizzazione","Sì — accelerare (più accordi) o rallentare (pedale) è anche una forma di riarmonizzazione","Sì, ma solo accelerando","No, la melodia impedisce qualsiasi cambiamento di ritmo"], a: 1, fb: "Il ritmo armonico (frequenza dei cambi di accordo) può essere modificato in una riarmonizzazione. Un pedale (accordo tenuto) o una suddivisione più densa sono strumenti di riarmonizzazione a tutti gli effetti." },
  { q: "Una riarmonizzazione può modificare la tonalità di un brano?", opts: ["No, mai","Sì — una riarmonizzazione può indurre una nuova tonalità","Sì, ma solo verso il relativo minore","Solo se si cambia anche il modo"], a: 1, fb: "Sì — una riarmonizzazione audace può scivolare verso una nuova tonalità implicita. È un modo di creare una modulazione progressiva e fluida, senza una brusca rottura." },
  { q: "Quale stile musicale ha reso popolare la riarmonizzazione come tecnica di arrangiamento codificata?", opts: ["La musica classica barocca","Il jazz degli anni 1950–1970","La musica folk","La musica contemporanea dodecafonica"], a: 1, fb: "Il jazz degli anni 1950–1970 — in particolare il jazz modale e post-bop — ha reso popolare la riarmonizzazione sistematica. Miles Davis, Bill Evans e i loro contemporanei hanno elevato questa tecnica al rango di arte." },
  { q: "Qual è la differenza tra sostituzione e riarmonizzazione?", opts: ["Sono sinonimi esatti","La sostituzione sostituisce un accordo, la riarmonizzazione trasforma un'intera progressione","La sostituzione è più avanzata","La riarmonizzazione non cambia la melodia"], a: 1, fb: "La sostituzione indica la sostituzione di un accordo specifico (es. Sol7 → Re♭7). La riarmonizzazione è un termine più ampio che può trasformare un'intera progressione — comprende la sostituzione e altre tecniche." },
  { q: "Cos'è la sostituzione diatonica?", opts: ["Sostituire un accordo con il suo accordo di dominante","Sostituire un accordo con un altro accordo diatonico che condivide note comuni","Aggiungere la 7ª a tutti gli accordi","Sostituire gli accordi minori con maggiori"], a: 1, fb: "La sostituzione diatonica sostituisce un accordo con un altro accordo della stessa scala (diatonico) che condivide note comuni. Gli accordi a distanza di terza sono i migliori candidati — condividono 2 note su 3." },
  { q: "Perché gli accordi a distanza di terza sono buoni sostituti diatonici?", opts: ["Hanno la stessa fondamentale","Condividono 2 note comuni su 3 (triade)","Sono sempre della stessa qualità","Creano esattamente lo stesso colore"], a: 1, fb: "In Do maggiore: DoMag (C E G) e Mim (E G B) condividono Mi e Sol. Questa comunità di note garantisce che la melodia resti compatibile — è il principio della sostituzione diatonica." },
  { q: "Quale accordo è il sostituto diatonico naturale di I (accordo di tonica)?", opts: ["IV","V","VI (relativo minore)","VII"], a: 2, fb: "VIm (relativo minore) è il sostituto diatonico naturale di I. In Do maggiore: Lam sostituisce DoMag — condividono Do e Mi, due delle tre note della triade." },
  { q: "In Do maggiore, quale accordo può sostituire Rem7 per sostituzione diatonica?", opts: ["SolMaj7","FaMaj7","Sim7♭5","DoMaj7"], a: 1, fb: "FaMaj7 può sostituire Rem7 — condividono Fa, La, Do (3 note comuni). FaMaj7 = F A C E; Rem7 = D F A C. Tre note comuni: Fa, La, Do." },
  { q: "La progressione II–V–I (Rem7–Sol7–DoMaj7) riarmonizzata come FaMaj7–Mim7–DoMaj7 illustra:", opts: ["Sostituzione di tritono","Sostituzione diatonica dei primi due accordi","Prestito modale","Armonizzazione parallela"], a: 1, fb: "FaMaj7 sostituisce Rem7 (3 note comuni: F A C), Mim7 sostituisce Sol7 (3 note comuni: G B D). Doppia sostituzione diatonica — la tensione del II–V si attenua, il colore diventa più modale." },
  { q: "In Sol maggiore, quale accordo è il sostituto diatonico naturale di SolMaj7 (I)?", opts: ["Lam7 (II)","Sim7 (III)","Mim7 (VI)","Re7 (V)"], a: 2, fb: "Mim7 (VIm) è il sostituto diatonico naturale di SolMaj7 (I) in Sol maggiore. SolMaj7 = G B D F#; Mim7 = E G B D. Condividono Sol, Si, Re — tre note comuni." },
  { q: "Qual è il rischio principale della sostituzione diatonica?", opts: ["Uscire dalla tonalità","Perdere la tensione armonica dell'originale (il V7 perde la sua funzione di dominante)","Rendere la progressione troppo complessa","Creare movimenti del basso paralleli"], a: 1, fb: "Sostituendo V7, si può perdere la tensione di dominante. Questo è un rischio (meno tensione) ma anche un vantaggio (atmosfera più modale, meno tonale)." },
  { q: "Mim7 → Sol7 in Do maggiore illustra quale relazione diatonica?", opts: ["Sostituto a distanza di 2ª","IIIm sostituisce V7 (condividono G, B, D)","Sostituto a distanza di quinta","Sostituto di sottodominante"], a: 1, fb: "Mim7 e Sol7 condividono Sol, Si, Re — tre note comuni. Mim7 può sostituire Sol7 creando un colore meno teso. È la sostituzione mediante IIIm del V grado." },
  { q: "La sostituzione diatonica preserva sempre:", opts: ["La qualità (maggiore/minore) dell'accordo originale","La funzione armonica dell'accordo originale","La tonalità generale della progressione","La nota del basso originale"], a: 2, fb: "La sostituzione diatonica rimane nella stessa scala — preserva la tonalità generale. Può però modificare la funzione e la qualità dell'accordo." },
  { q: "Cos'è la sostituzione di tritono?", opts: ["Sostituire qualsiasi accordo con la sua trasposizione di tritono","Sostituire V7 con l'accordo di dominante situato un tritono più in basso","Aggiungere un tritono all'accordo di dominante","Usare accordi aumentati"], a: 1, fb: "La sostituzione di tritono sostituisce V7 con l'accordo di dominante situato un tritono più in basso (6 semitoni). Sol7 → Re♭7. Questi due accordi condividono i loro guide-tones (terza e settima invertiti)." },
  { q: "Perché Sol7 e Re♭7 sono sostituti di tritono l'uno dell'altro?", opts: ["Hanno la stessa fondamentale all'ottava superiore","Condividono gli stessi guide-tones: Si/Do♭ e Fa (enarmonici)","Entrambi sono in modo dorico","Hanno la stessa quinta"], a: 1, fb: "Sol7 guide-tones: Si (3ª) e Fa (7ª). Re♭7 guide-tones: Fa (3ª) e Do♭/Si (7ª). Si e Do♭ sono enarmonici, Fa è comune. Queste due note di tensione sono condivise." },
  { q: "Qual è il sostituto di tritono di Do7?", opts: ["Fa7","Sol♭7","Sol7","Mi♭7"], a: 1, fb: "Sol♭7 è il sostituto di tritono di Do7. Distanza Do → Sol♭ = 6 semitoni. Do7 guide-tones: Mi (3ª) e Si♭ (7ª); Sol♭7 guide-tones: Si♭ (3ª) e Fa♭/Mi (7ª)." },
  { q: "Quale effetto crea la sostituzione di tritono sul basso?", opts: ["Basso che sale di una quinta","Basso cromatico discendente (es. Sol → Re♭ → Do)","Basso statico","Basso che scende per quinte"], a: 1, fb: "La sostituzione di tritono crea un basso cromatico discendente. In II–V–I in Do con sub tritonica su V: Re → Re♭ → Do. Questo movimento di ½ tono Re♭→Do è molto espressivo e fluente." },
  { q: "La sostituzione di tritono si applica principalmente a:", opts: ["Tutti i tipi di accordi","Accordi di tonica (Maj7)","Accordi di dominante (7ª)","Accordi di sottodominante minori"], a: 2, fb: "La sostituzione di tritono si applica principalmente agli accordi di dominante (7ª). Il tritono interno del V7 (guide-tone) è la condizione necessaria." },
  { q: "In Autumn Leaves in Dom, la sostituzione di tritono di Sol7 dà:", opts: ["Do7","Fa#7 / Sol♭7","Re♭7","La♭7"], a: 2, fb: "Sol7 → Re♭7 (tritono di Sol). Il basso diventa: Rem7♭5 (Re) → Re♭7 (Re♭) → Dom (Do) — movimento cromatico Re → Re♭ → Do. È una delle riarmonizzazioni più celebrate nel jazz." },
  { q: "La sostituzione di tritono è stata sviluppata principalmente nel:", opts: ["Musica barocca (XVII secolo)","Jazz bebop (anni 1940–1950)","Musica seriale (XX secolo)","Impressionismo (inizio XX secolo)"], a: 1, fb: "La sostituzione di tritono è stata sviluppata nel bebop degli anni 1940–1950, resa popolare da Charlie Parker, Dizzy Gillespie e Thelonious Monk." },
  { q: "Qual è il sostituto di tritono di Re7?", opts: ["Sol#7 / La♭7","La7","Mi♭7 / Re♯7","Fa7"], a: 0, fb: "La♭7 è il sostituto di tritono di Re7. Distanza Re → La♭ = 6 semitoni. Re7 guide-tones: Fa# (3ª) e Do (7ª). La♭7 guide-tones: Do (3ª) e Sol♭ (7ª = Fa# enarmonico)." },
  { q: "Qual è il sostituto di tritono di Fa7?", opts: ["Si7","Do7","Mi7","Sol7"], a: 0, fb: "Si7 è il sostituto di tritono di Fa7. Distanza Fa → Si = 6 semitoni. Fa7 guide-tones: La (3ª) e Mi♭ (7ª). Si7 guide-tones: Re# (3ª = Mi♭ enarmonico) e La (7ª)." },
  { q: "Si può applicare la sostituzione di tritono a una dominante secondaria?", opts: ["No, solo al V7 principale","Sì — il V7/II (La7 in Do) può essere sostituito da Mi♭7","Sì, ma solo se è il V7/IV","Solo se la progressione dura almeno 2 battute"], a: 1, fb: "Sì — la sostituzione di tritono si applica a qualsiasi accordo di dominante, comprese le dominanti secondarie. V7/II = La7 in Do maggiore → Mi♭7 (tritono di La)." },
  { q: "Cos'è un prestito modale?", opts: ["Usare scale modali in una progressione tonale","Prendere in prestito un accordo dal modo parallelo (stessa tonica, modo diverso)","Trasporre un accordo in un altro modo","Usare il modo lidio su un accordo maggiore"], a: 1, fb: "Il prestito modale consiste nel prendere in prestito un accordo dal modo parallelo — stessa tonica, modo diverso. In Do maggiore, Fam7 è preso in prestito da Do minore. La tonica rimane la stessa; si prende in prestito il colore del minore." },
  { q: "In Do maggiore, quali accordi sono tipicamente presi in prestito dal modo minore parallelo?", opts: ["Lam7, Mim7, Rem7","♭VIMaj7, ♭VIIMaj7, IVm7","II7, III7, VI7","VIIdim, IVdim, IIdim"], a: 1, fb: "Prestiti classici dal minore parallelo in Do maggiore: Fam7 (IVm), La♭Maj7 (♭VI), Si♭Maj7 (♭VII). Questi accordi bemollizzati introducono ♭ estranei a Do maggiore ma naturali in Do minore." },
  { q: "L'accordo ♭VIIMaj7 in Do maggiore (Si♭Maj7) è preso in prestito da:", opts: ["Sol misolidio","Do minore (eolico)","Fa lidio","Re dorico"], a: 1, fb: "Si♭Maj7 = ♭VIIMaj7 in Do maggiore. In Do minore naturale (eolico), il VII grado è Si♭ — è l'accordo ♭VII naturale del minore, preso in prestito dal modo minore parallelo." },
  { q: "La successione DoMaj7 → Dom7 illustra:", opts: ["Sostituzione di tritono","Prestito modale (stessa tonica, colore maggiore → minore)","Armonizzazione parallela","Sostituzione diatonica"], a: 1, fb: "DoMaj7 → Dom7: stessa fondamentale Do, passaggio dal modo maggiore al minore. Questo è il cuore del prestito modale — stessa tonica, colore diverso. Bill Evans sfrutta questo gesto in Peace Piece." },
  { q: "Bill Evans usa il prestito modale in Peace Piece:", opts: ["Sostituendo Sol7 con Re♭7","Prendendo in prestito Dom7 e Fam7 dal modo Do minore su un pedale di Do","Usando scale pentatoniche","Trasponendo la melodia al modo dorico"], a: 1, fb: "In Peace Piece, Evans mantiene Do come pedale di basso e prende in prestito Dom7 e Fam7 dal Do minore parallelo. Questa oscillazione Maj7 ↔ m7 crea il colore meditativo caratteristico del brano." },
  { q: "In Sol maggiore, quale accordo è il prestito modale ♭VIMaj7?", opts: ["Mi♭Maj7","FaMaj7","Si♭Maj7","La♭Maj7"], a: 0, fb: "♭VI in Sol = Mi♭. Mi♭Maj7 è preso in prestito da Sol minore (Sol eolico) dove il VI grado è Mi♭. È un accordo molto espressivo in una progressione in Sol maggiore." },
  { q: "L'accordo IVm in una tonalità maggiore (es. Fam in Do) crea quale effetto?", opts: ["Chiarezza e stabilità rafforzate","Un colore scuro inaspettato dovuto alla terza minore e alla 7ª bemollizzata prese in prestito","Maggiore tensione di dominante","Risoluzione plagale pura"], a: 1, fb: "Fam7 = F La♭ Do Mi♭. Il La♭ e il Mi♭ sono presi in prestito da Do minore. Queste note ♭ creano un colore scuro inaspettato in un contesto maggiore — è precisamente l'effetto ricercato." },
  { q: "Si possono prendere in prestito accordi da modi diversi dal minore parallelo?", opts: ["No, solo dal minore parallelo","Sì — frigio, lidio, dorico, ecc. sono anche fonti di prestiti","Sì, ma solo nel jazz","Solo per gli accordi di sottodominante"], a: 1, fb: "Sì — si può prendere in prestito da qualsiasi modo parallelo. ♭II (dal frigio), #IV (dal lidio), ♭VI (dal misolidio o eolico), ecc. Più il modo è lontano, più il colore è sorprendente." },
  { q: "Cos'è l'armonizzazione parallela?", opts: ["Armonizzare una melodia con due voci alla terza","Trasporre un blocco di accordi della stessa qualità per moto congiunto (semitoni o toni)","Raddoppiare la melodia all'ottava inferiore","Usare accordi paralleli a distanza di quinta"], a: 1, fb: "L'armonizzazione parallela consiste nel trasporre un blocco di accordi (della stessa qualità) per moto congiunto. DoMaj7 → SiMaj7 → Si♭Maj7: tre Maj7 che scendono cromaticamente." },
  { q: "Il parallelismo cromatico con accordi Maj7 è associato a:", opts: ["Il contrappunto barocco rigoroso","L'impressionismo francese e il jazz modale (Debussy, Bill Evans)","La musica seriale","Il blues tradizionale"], a: 1, fb: "Il parallelismo cromatico con Maj7 è la firma dell'impressionismo (Debussy) e del jazz modale (Bill Evans, Herbie Hancock). È uno dei suoni più 'contemporanei' in armonia." },
  { q: "In un'armonizzazione parallela, la melodia:", opts: ["Deve necessariamente muoversi per gradi congiunti","Può restare su una nota tenuta mentre gli accordi si muovono","Deve seguire la stessa direzione degli accordi","Deve essere raddoppiata alla terza inferiore"], a: 1, fb: "La nota melodica può restare tenuta (pedale melodico) mentre gli accordi scendono cromaticamente. Questa tensione tra melodia fissa e armonia mobile è molto espressiva." },
  { q: "DoMaj7 → SiMaj7 → Si♭Maj7 illustra un'armonizzazione parallela:", opts: ["Per toni interi","Cromatica discendente (½ tono ½ tono)","Per terze discendenti","Per quinte discendenti"], a: 1, fb: "Do → Si → Si♭: ogni fondamentale scende di un semitono. È il parallelismo cromatico — il più espressivo nel jazz moderno." },
  { q: "Quale compositore classico ha reso popolari gli accordi in scivolamento parallelo?", opts: ["Debussy","Beethoven","Brahms","Schoenberg"], a: 0, fb: "Claude Debussy ha reso popolari gli accordi in scivolamento parallelo nell'impressionismo. In 'La cattedrale sommersa', blocchi paralleli creano il caratteristico colore organistico." },
  { q: "Perché l'armonizzazione parallela 'libera' gli accordi dalle loro funzioni tonali?", opts: ["Elimina gli accordi di dominante","Gli accordi paralleli creano un colore, non una tensione-risoluzione — pensiero coloristico","Cambia la tonalità ad ogni accordo","Usa solo accordi di sottodominante"], a: 1, fb: "Nel parallelismo, gli accordi non svolgono più il loro ruolo funzionale (T/SD/D) — ogni accordo è un colore in sé. È il pensiero modale/coloristico piuttosto che funzionale/tonale." },
  { q: "Confrontando sostituzione diatonica e tritonica: quale affermazione è vera?", opts: ["La diatonica si applica a V7, la tritonica a tutti gli accordi","La sostituzione tritonica si applica specificamente a V7; la diatonica si applica a tutti i gradi","Entrambe si applicano solo agli accordi minori","La diatonica esce dalla scala, la tritonica no"], a: 1, fb: "La sostituzione tritonica mira specificamente a V7 (e alle dominanti secondarie). La sostituzione diatonica si applica a qualsiasi grado della scala." },
  { q: "Quale tecnica crea il movimento del basso più cromatico?", opts: ["Sostituzione diatonica","Prestito modale","Sostituzione di tritono","Armonizzazione parallela per toni"], a: 2, fb: "La sostituzione di tritono crea il movimento del basso cromatico più diretto: V7 → sub(V7) → I dà ½ tono → I (es. Sol → Re♭ → Do). È la più espressiva e la più 'jazz'." },
  { q: "Quale tecnica è la più 'morbida' (meno cromatica, nella tonalità)?", opts: ["Sostituzione di tritono","Prestito modale","Armonizzazione parallela cromatica","Sostituzione diatonica"], a: 3, fb: "La sostituzione diatonica rimane interamente nella scala — non esce mai dalla tonalità. È la tecnica meno cromatica, la più 'interiore' alla tonalità." },
  { q: "Bill Evans è nato e morto in:", opts: ["1910–1975","1929–1980","1945–1990","1920–1965"], a: 1, fb: "Bill Evans (1929–1980) è uno dei pianisti jazz più influenti del XX secolo. Le sue innovazioni armoniche — riarmonizzazioni, voicings in cluster, prestiti modali — hanno definito il piano jazz moderno." },
  { q: "Quale album di Miles Davis (con Bill Evans) è fondante per il jazz modale?", opts: ["A Love Supreme","Kind of Blue (1959)","Bitches Brew","Sketches of Spain"], a: 1, fb: "Kind of Blue (1959) è l'album jazz più venduto di tutti i tempi. Bill Evans ha contribuito alle note di copertina. So What, Flamenco Sketches — ognuno illustra un approccio modale distinto." },
  { q: "Brad Mehldau è particolarmente noto per le sue riarmonizzazioni di:", opts: ["Solo Bach e Haendel","Standard jazz e canzoni pop/rock (Radiohead, Beatles)","Musica per film","Opere italiane"], a: 1, fb: "Brad Mehldau (nato nel 1970) è famoso per le sue reinterpretazioni jazz di pop e rock — Radiohead (Exit Music for a Film), Beatles (Blackbird). Le sue riarmonizzazioni trasformano queste melodie note in opere jazz sofisticate." },
  { q: "La progressione 'Coltrane changes' (Giant Steps) usa quale principio?", opts: ["Solo sostituzioni diatoniche","Un ciclo di terze maggiori che divide l'ottava in 3 parti uguali","Armonizzazione parallela a blocchi","Prestiti modali dal modo frigio"], a: 1, fb: "John Coltrane in Giant Steps (1960) divide l'ottava in tre terze maggiori: Si – Sol – Mi♭ – Si. Ogni tonalità dura solo 2 tempi. È una riarmonizzazione radicale che sostituisce il ciclo delle quinte." },
  { q: "Quale pianista classico ha fortemente influenzato l'armonizzazione parallela jazz?", opts: ["Rachmaninov","Debussy (impressionismo francese)","Brahms","Bartók"], a: 1, fb: "Claude Debussy (1862–1918) ha influenzato direttamente il jazz attraverso i suoi accordi paralleli, scale per toni e colori armonici non funzionali. Bill Evans citava Debussy come influenza principale." },
  { q: "Quale affermazione descrive meglio la riarmonizzazione come strumento creativo?", opts: ["È una tecnica per correggere armonie errate","È l'arte di trasformare il colore armonico di un'opera rispettando la sua melodia — una firma personale","È solo una tecnica pedagogica","È una tecnica di semplificazione per principianti"], a: 1, fb: "La riarmonizzazione è una firma musicale personale. Bill Evans, Miles Davis, Keith Jarrett, Brad Mehldau — ognuno ha sviluppato un linguaggio riconoscibile. È l'arte di trasformare un'opera in espressione personale, rispettando la melodia." },
  { q: "Per riarmonizzare una progressione gospel I–IV–I–V, quale tecnica sarebbe idiomatica?", opts: ["Sostituzioni di tritono su ogni accordo","Prestiti modali (IVm, ♭VII) per aggiungere colore minore in un contesto maggiore","Armonizzazione parallela cromatica","Coltrane Changes"], a: 1, fb: "Il gospel usa frequentemente i prestiti modali — IVm (Fam in Do), ♭VI, ♭VII — che introducono il colore blues in un contesto maggiore. La progressione I – IVm – I – V è caratteristica del gospel." },
  { q: "Quale illustra una doppia tecnica: prestito modale + armonizzazione parallela?", opts: ["Rem7 → Sol7 → DoMaj7","DoMaj7 → Dom7 → Fam7 poi Fam7 → MiMaj7 → Mi♭Maj7","Sol7 → Re♭7 → Do","Lam7 → FaMaj7 → Sol7"], a: 1, fb: "DoMaj7 → Dom7 → Fam7: prestito modale (Do minore). Poi Fam7 → MiMaj7 → Mi♭Maj7: armonizzazione parallela cromatica discendente. La combinazione crea una progressione molto 'Bill Evans'." },
];

const questionsPt: Question[] = [
  { q: "O que é rearmonização?", opts: ["Transpor uma melodia para outra tonalidade","Substituir os acordes de uma progressão conservando a melodia","Acrescentar extensões a todos os acordes","Mudar o ritmo harmônico"], a: 1, fb: "A rearmonização consiste em substituir os acordes de uma progressão existente por outros acordes, conservando a melodia intacta. É a arte de mudar 'o chão' sem tocar 'o teto'." },
  { q: "Qual é a restrição fundamental da rearmonização?", opts: ["Os novos acordes devem estar na mesma tonalidade","A melodia deve permanecer compatível com os novos acordes","O ritmo harmônico deve dobrar","Os acordes devem ser mais complexos"], a: 1, fb: "A melodia deve permanecer compatível com os novos acordes — esta é a restrição fundamental. A nota melódica deve ser consonante com cada novo acorde (fundamental, terça, quinta, 7ª, 9ª, 11ª, 13ª)." },
  { q: "O que é um 'guide-tone'?", opts: ["A nota mais alta do acorde","A terça e a sétima de um acorde de dominante","A fundamental e a quinta","A 9ª de um acorde estendido"], a: 1, fb: "Os guide-tones são a terça e a sétima de um acorde de dominante. Essas duas notas definem o trítono característico — são o coração das substituições de trítono." },
  { q: "Qual compositor é famoso pelas suas rearmonizações impressionistas?", opts: ["Beethoven","Mozart","Bill Evans","Haendel"], a: 2, fb: "Bill Evans (1929–1980) é um dos maiores mestres da rearmonização. Suas rearmonizações de standards de jazz, usando empréstimos modais e harmonização paralela, revolucionaram o piano jazz." },
  { q: "Por que rearmonizar?", opts: ["Para facilitar a leitura","Para corrigir um erro harmônico","Para enriquecer a cor, criar interesse, personalizar o arranjo","Para encurtar a progressão"], a: 2, fb: "Rearmonizamos para enriquecer a cor harmônica, criar interesse ou surpresa, personalizar um arranjo, ou expressar uma visão musical diferente." },
  { q: "Uma nota melódica é 'compatível' com um acorde se:", opts: ["É apenas a fundamental do acorde","É fundamental, 3ª, 5ª, 7ª, 9ª, #11 ou 13ª do acorde","Não está no acorde","É a nota mais alta do acorde"], a: 1, fb: "Uma nota é compatível se pertence às extensões do acorde: fundamental, terça, quinta, 7ª, 9ª, 11ª aumentada (#4), 13ª. Notas de tensão forte (9ª menor, 11ª justa em acorde maior) são geralmente a evitar." },
  { q: "Qual é a avoid note clássica num acorde Maj7?", opts: ["A 9ª","A 4ª justa (11ª natural)","A 6ª maior","A 7ª menor"], a: 1, fb: "A 4ª justa (11ª natural) é a avoid note clássica num acorde Maj7. Em CMaj7, Fá está a ½ tom de Mi (terça do acorde) — dissonância de ½ tom muito forte. No jazz prefere-se Fá# (#11)." },
  { q: "Que movimento do baixo é frequentemente criado por uma boa rearmonização?", opts: ["Baixo estático","Baixo por saltos de oitava","Baixo com movimento cromático ou por graus conjuntos","Baixo por quintas"], a: 2, fb: "Uma rearmonização eficaz cria frequentemente um movimento de baixo cromático ou por graus conjuntos — ex. Ré → Ré♭ → Dó na substituição de trítono em Autumn Leaves. Este movimento fluente é uma marca das melhores rearmonizações." },
  { q: "A rearmonização é particularmente usada em:", opts: ["A música barroca","A música serial","O jazz e a música impressionista","A polifonia medieval"], a: 2, fb: "A rearmonização é central no jazz (Bill Evans, Miles Davis, Brad Mehldau) e na música impressionista (Debussy, Ravel). Esses estilos partilham o gosto pela cor harmônica em vez da tensão-resolução." },
  { q: "Numa rearmonização, qual parâmetro NÃO muda por definição?", opts: ["Os acordes","A melodia","O ritmo harmônico","A tonalidade geral"], a: 1, fb: "Por definição, a rearmonização conserva a melodia intacta. É o princípio fundador: os acordes mudam 'sob' a melodia, que permanece a mesma." },
  { q: "A noção de harmonia 'funcional' vs harmonia 'colorista' é central porque:", opts: ["Uma é jazz e a outra clássica","A harmonização funcional cria tensão-resolução, a colorista cria atmosferas","A colorista é apenas modal","A funcional é apenas diatônica"], a: 1, fb: "Harmonia funcional: os acordes criam tensão–resolução. Harmonia colorista: os acordes são cores autônomas. A rearmonização pode ir para mais colorismo (Evans, Debussy) ou permanecer funcional (bebop)." },
  { q: "Pode-se rearmonizar modificando o ritmo harmônico?", opts: ["Não, o ritmo harmônico não faz parte da rearmonização","Sim — acelerar (mais acordes) ou abrandar (pedais) é também uma forma de rearmonização","Sim, mas apenas acelerando","Não, a melodia impede qualquer mudança de ritmo"], a: 1, fb: "O ritmo harmônico (frequência das mudanças de acordes) pode ser modificado numa rearmonização. Um pedal (acorde sustentado) ou uma subdivisão mais densa são ferramentas de rearmonização por direito próprio." },
  { q: "Uma rearmonização pode modificar a tonalidade de uma peça?", opts: ["Não, nunca","Sim — uma rearmonização pode induzir uma nova tonalidade","Sim, mas apenas para o relativo menor","Apenas se também se mudar o modo"], a: 1, fb: "Sim — uma rearmonização ousada pode deslizar para uma nova tonalidade implícita. É uma maneira de criar uma modulação progressiva e fluente, sem ruptura brusca." },
  { q: "Qual estilo musical popularizou a rearmonização como técnica de arranjo codificada?", opts: ["A música clássica barroca","O jazz dos anos 1950–1970","A música folk","A música contemporânea dodecafônica"], a: 1, fb: "O jazz dos anos 1950–1970 — em especial o jazz modal e post-bop — popularizou a rearmonização sistemática. Miles Davis, Bill Evans e seus contemporâneos elevaram esta técnica ao nível de arte." },
  { q: "Qual é a diferença entre substituição e rearmonização?", opts: ["São sinônimos exatos","A substituição substitui um acorde, a rearmonização transforma toda uma progressão","A substituição é mais avançada","A rearmonização não muda a melodia"], a: 1, fb: "A substituição designa a substituição de um acorde específico (ex. Sol7 → Ré♭7). A rearmonização é um termo mais amplo que pode transformar toda uma progressão — engloba a substituição e outras técnicas." },
  { q: "O que é substituição diatônica?", opts: ["Substituir um acorde pelo seu acorde de dominante","Substituir um acorde por outro acorde diatônico que partilha notas comuns","Acrescentar a 7ª a todos os acordes","Substituir os acordes menores por maiores"], a: 1, fb: "A substituição diatônica substitui um acorde por outro acorde da mesma escala (diatônico) que partilha notas comuns. Os acordes a distância de terça são os melhores candidatos — partilham 2 notas em 3." },
  { q: "Por que os acordes a distância de terça são bons substitutos diatônicos?", opts: ["Têm a mesma fundamental","Partilham 2 notas comuns em 3 (tríade)","São sempre da mesma qualidade","Criam exatamente a mesma cor"], a: 1, fb: "Em Dó maior: DóMaj (C E G) e Mim (E G B) partilham Mi e Sol. Esta comunidade de notas garante que a melodia permaneça compatível — é o princípio da substituição diatônica." },
  { q: "Qual acorde é o substituto diatônico natural de I (acorde de tônica)?", opts: ["IV","V","VI (relativo menor)","VII"], a: 2, fb: "VIm (relativo menor) é o substituto diatônico natural de I. Em Dó maior: Lam substitui DóMaj — partilham Dó e Mi, duas das três notas da tríade." },
  { q: "Em Dó maior, qual acorde pode substituir Rem7 por substituição diatônica?", opts: ["SolMaj7","FáMaj7","Sim7♭5","DóMaj7"], a: 1, fb: "FáMaj7 pode substituir Rem7 — partilham Fá, Lá, Dó (3 notas comuns). FáMaj7 = F A C E; Rem7 = D F A C. Três notas comuns: Fá, Lá, Dó." },
  { q: "A progressão II–V–I (Rem7–Sol7–DóMaj7) rearmonizada como FáMaj7–Mim7–DóMaj7 ilustra:", opts: ["Substituição de trítono","Substituição diatônica dos dois primeiros acordes","Empréstimo modal","Harmonização paralela"], a: 1, fb: "FáMaj7 substitui Rem7 (3 notas comuns: F A C), Mim7 substitui Sol7 (3 notas comuns: G B D). Dupla substituição diatônica — a tensão do II–V dissipa-se, a cor torna-se mais modal." },
  { q: "Em Sol maior, qual acorde é o substituto diatônico natural de SolMaj7 (I)?", opts: ["Lam7 (II)","Sim7 (III)","Mim7 (VI)","Ré7 (V)"], a: 2, fb: "Mim7 (VIm) é o substituto diatônico natural de SolMaj7 (I) em Sol maior. SolMaj7 = G B D F#; Mim7 = E G B D. Partilham Sol, Si, Ré — três notas comuns." },
  { q: "Qual é o risco principal da substituição diatônica?", opts: ["Sair da tonalidade","Perder a tensão harmônica do original (o V7 perde a sua função de dominante)","Tornar a progressão demasiado complexa","Criar movimentos de baixo paralelos"], a: 1, fb: "Ao substituir V7, pode-se perder a tensão de dominante. Isso é um risco (menos tensão) mas também uma vantagem (atmosfera mais modal, menos tonal)." },
  { q: "Mim7 → Sol7 em Dó maior ilustra qual relação diatônica?", opts: ["Substituto a distância de 2ª","IIIm substitui V7 (partilham G, B, D)","Substituto a distância de quinta","Substituto de subdominante"], a: 1, fb: "Mim7 e Sol7 partilham Sol, Si, Ré — três notas comuns. Mim7 pode substituir Sol7 criando uma cor menos tensa. É a substituição pelo IIIm do V grau." },
  { q: "A substituição diatônica preserva sempre:", opts: ["A qualidade (maior/menor) do acorde original","A função harmônica do acorde original","A tonalidade geral da progressão","A nota do baixo original"], a: 2, fb: "A substituição diatônica permanece na mesma escala — preserva a tonalidade geral. Pode, no entanto, modificar a função e a qualidade do acorde." },
  { q: "O que é substituição de trítono?", opts: ["Substituir qualquer acorde pela sua transposição de trítono","Substituir V7 pelo acorde de dominante situado um trítono abaixo","Acrescentar um trítono ao acorde de dominante","Usar acordes aumentados"], a: 1, fb: "A substituição de trítono substitui V7 pelo acorde de dominante situado um trítono abaixo (6 semitons). Sol7 → Ré♭7. Esses dois acordes partilham os seus guide-tones (terça e sétima invertidas)." },
  { q: "Por que Sol7 e Ré♭7 são substitutos de trítono um do outro?", opts: ["Têm a mesma fundamental uma oitava acima","Partilham os mesmos guide-tones: Si/Dó♭ e Fá (enarmônicos)","Ambos estão em modo dórico","Têm a mesma quinta"], a: 1, fb: "Sol7 guide-tones: Si (3ª) e Fá (7ª). Ré♭7 guide-tones: Fá (3ª) e Dó♭/Si (7ª). Si e Dó♭ são enarmônicos, Fá é comum. Essas duas notas de tensão são partilhadas." },
  { q: "Qual é o substituto de trítono de Dó7?", opts: ["Fá7","Sol♭7","Sol7","Mi♭7"], a: 1, fb: "Sol♭7 é o substituto de trítono de Dó7. Distância Dó → Sol♭ = 6 semitons. Dó7 guide-tones: Mi (3ª) e Si♭ (7ª); Sol♭7 guide-tones: Si♭ (3ª) e Fá♭/Mi (7ª)." },
  { q: "Que efeito cria a substituição de trítono no baixo?", opts: ["Baixo que sobe uma quinta","Baixo cromático descendente (ex. Sol → Ré♭ → Dó)","Baixo estático","Baixo que desce por quintas"], a: 1, fb: "A substituição de trítono cria um baixo cromático descendente. Em II–V–I em Dó com sub tritônica em V: Ré → Ré♭ → Dó. Este movimento de ½ tom Ré♭→Dó é muito expressivo e fluente." },
  { q: "A substituição de trítono aplica-se principalmente a:", opts: ["Todos os tipos de acordes","Acordes de tônica (Maj7)","Acordes de dominante (7ª)","Acordes de subdominante menores"], a: 2, fb: "A substituição de trítono aplica-se principalmente aos acordes de dominante (7ª). O trítono interno do V7 (guide-tone) é a condição necessária." },
  { q: "Em Autumn Leaves em Dóm, a substituição de trítono de Sol7 dá:", opts: ["Dó7","Fá#7 / Sol♭7","Ré♭7","Lá♭7"], a: 2, fb: "Sol7 → Ré♭7 (trítono de Sol). O baixo torna-se: Rem7♭5 (Ré) → Ré♭7 (Ré♭) → Dóm (Dó) — movimento cromático Ré → Ré♭ → Dó. É uma das rearmonizações mais célebres do jazz." },
  { q: "A substituição de trítono foi desenvolvida principalmente no:", opts: ["Música barroca (século XVII)","Jazz bebop (anos 1940–1950)","Música serial (século XX)","Impressionismo (início do século XX)"], a: 1, fb: "A substituição de trítono foi desenvolvida no bebop dos anos 1940–1950, popularizada por Charlie Parker, Dizzy Gillespie e Thelonious Monk." },
  { q: "Qual é o substituto de trítono de Ré7?", opts: ["Sol#7 / Lá♭7","Lá7","Mi♭7 / Ré♯7","Fá7"], a: 0, fb: "Lá♭7 é o substituto de trítono de Ré7. Distância Ré → Lá♭ = 6 semitons. Ré7 guide-tones: Fá# (3ª) e Dó (7ª). Lá♭7 guide-tones: Dó (3ª) e Sol♭ (7ª = Fá# enarmônico)." },
  { q: "Qual é o substituto de trítono de Fá7?", opts: ["Si7","Dó7","Mi7","Sol7"], a: 0, fb: "Si7 é o substituto de trítono de Fá7. Distância Fá → Si = 6 semitons. Fá7 guide-tones: Lá (3ª) e Mi♭ (7ª). Si7 guide-tones: Ré# (3ª = Mi♭ enarmônico) e Lá (7ª)." },
  { q: "Pode-se aplicar a substituição de trítono a uma dominante secundária?", opts: ["Não, apenas ao V7 principal","Sim — o V7/II (Lá7 em Dó) pode ser substituído por Mi♭7","Sim, mas apenas se for o V7/IV","Apenas se a progressão durar pelo menos 2 compassos"], a: 1, fb: "Sim — a substituição de trítono aplica-se a qualquer acorde de dominante, incluindo as dominantes secundárias. V7/II = Lá7 em Dó maior → Mi♭7 (trítono de Lá)." },
  { q: "O que é um empréstimo modal?", opts: ["Usar escalas modais numa progressão tonal","Tomar emprestado um acorde do modo paralelo (mesma tônica, modo diferente)","Transpor um acorde para outro modo","Usar o modo lídio num acorde maior"], a: 1, fb: "O empréstimo modal consiste em tomar emprestado um acorde do modo paralelo — mesma tônica, modo diferente. Em Dó maior, Fám7 é emprestado de Dó menor. A tônica permanece a mesma; empresta-se a cor do menor." },
  { q: "Em Dó maior, quais acordes são tipicamente emprestados do modo menor paralelo?", opts: ["Lam7, Mim7, Rem7","♭VIMaj7, ♭VIIMaj7, IVm7","II7, III7, VI7","VIIdim, IVdim, IIdim"], a: 1, fb: "Empréstimos clássicos do menor paralelo em Dó maior: Fám7 (IVm), Lá♭Maj7 (♭VI), Si♭Maj7 (♭VII). Esses acordes bemolizados introduzem ♭ estranhos a Dó maior mas naturais em Dó menor." },
  { q: "O acorde ♭VIIMaj7 em Dó maior (Si♭Maj7) é emprestado de:", opts: ["Sol mixolídio","Dó menor (eólio)","Fá lídio","Ré dórico"], a: 1, fb: "Si♭Maj7 = ♭VIIMaj7 em Dó maior. Em Dó menor natural (eólio), o VII grau é Si♭ — é o acorde ♭VII natural do menor, emprestado do modo menor paralelo." },
  { q: "A sucessão DóMaj7 → Dóm7 ilustra:", opts: ["Substituição de trítono","Empréstimo modal (mesma tônica, cor maior → menor)","Harmonização paralela","Substituição diatônica"], a: 1, fb: "DóMaj7 → Dóm7: mesma fundamental Dó, passagem do modo maior ao menor. Este é o coração do empréstimo modal — mesma tônica, cor diferente. Bill Evans explora este gesto em Peace Piece." },
  { q: "Bill Evans usa o empréstimo modal em Peace Piece:", opts: ["Substituindo Sol7 por Ré♭7","Emprestando Dóm7 e Fám7 do modo Dó menor sobre um pedal de Dó","Usando escalas pentatônicas","Transpondo a melodia para o modo dórico"], a: 1, fb: "Em Peace Piece, Evans mantém Dó como pedal de baixo e empresta Dóm7 e Fám7 do Dó menor paralelo. Esta oscilação Maj7 ↔ m7 cria a cor meditativa característica da peça." },
  { q: "Em Sol maior, qual acorde é o empréstimo modal ♭VIMaj7?", opts: ["Mi♭Maj7","FáMaj7","Si♭Maj7","Lá♭Maj7"], a: 0, fb: "♭VI em Sol = Mi♭. Mi♭Maj7 é emprestado de Sol menor (Sol eólio) onde o VI grau é Mi♭. É um acorde muito expressivo numa progressão em Sol maior." },
  { q: "O acorde IVm numa tonalidade maior (ex. Fám em Dó) cria que efeito?", opts: ["Clareza e estabilidade reforçadas","Uma cor escura inesperada devido à terça menor e à 7ª bemolizada emprestadas","Maior tensão de dominante","Resolução plagal pura"], a: 1, fb: "Fám7 = F Lá♭ Dó Mi♭. O Lá♭ e o Mi♭ são emprestados de Dó menor. Estas notas ♭ criam uma cor escura inesperada num contexto maior — é precisamente o efeito pretendido." },
  { q: "Podem-se emprestar acordes de outros modos que não o menor paralelo?", opts: ["Não, apenas do menor paralelo","Sim — frígio, lídio, dórico, etc. são também fontes de empréstimos","Sim, mas apenas no jazz","Apenas para os acordes de subdominante"], a: 1, fb: "Sim — pode-se emprestar de qualquer modo paralelo. ♭II (do frígio), #IV (do lídio), ♭VI (do mixolídio ou eólio), etc. Quanto mais distante o modo, mais surpreendente a cor." },
  { q: "O que é harmonização paralela?", opts: ["Harmonizar uma melodia com duas vozes à terça","Transpor um bloco de acordes da mesma qualidade por movimento conjunto (semitons ou tons)","Dobrar a melodia à oitava inferior","Usar acordes paralelos a distância de quinta"], a: 1, fb: "A harmonização paralela consiste em transpor um bloco de acordes (da mesma qualidade) por movimento conjunto. DóMaj7 → SiMaj7 → Si♭Maj7: três Maj7 descendo cromaticamente." },
  { q: "O paralelismo cromático com acordes Maj7 está associado a:", opts: ["O contraponto barroco estrito","O impressionismo francês e o jazz modal (Debussy, Bill Evans)","A música serial","O blues tradicional"], a: 1, fb: "O paralelismo cromático com Maj7 é a assinatura do impressionismo (Debussy) e do jazz modal (Bill Evans, Herbie Hancock). É um dos sons mais 'contemporâneos' em harmonia." },
  { q: "Numa harmonização paralela, a melodia:", opts: ["Deve necessariamente mover-se por graus conjuntos","Pode permanecer numa nota sustentada enquanto os acordes se movem","Deve seguir a mesma direção que os acordes","Deve ser dobrada à terça inferior"], a: 1, fb: "A nota melódica pode permanecer sustentada (pedal melódico) enquanto os acordes descem cromaticamente. Esta tensão entre melodia fixa e harmonia móvel é muito expressiva." },
  { q: "DóMaj7 → SiMaj7 → Si♭Maj7 ilustra uma harmonização paralela:", opts: ["Por tons inteiros","Cromática descendente (½ tom ½ tom)","Por terças descendentes","Por quintas descendentes"], a: 1, fb: "Dó → Si → Si♭: cada fundamental desce um semitom. É o paralelismo cromático — o mais expressivo no jazz moderno." },
  { q: "Qual compositor clássico popularizou os acordes em deslizamento paralelo?", opts: ["Debussy","Beethoven","Brahms","Schoenberg"], a: 0, fb: "Claude Debussy popularizou os acordes em deslizamento paralelo no impressionismo. Em 'La cathédrale engloutie', blocos paralelos criam a característica cor de órgão." },
  { q: "Por que a harmonização paralela 'liberta' os acordes das suas funções tonais?", opts: ["Elimina os acordes de dominante","Os acordes paralelos criam uma cor, não uma tensão-resolução — pensamento colorista","Muda a tonalidade a cada acorde","Usa apenas acordes de subdominante"], a: 1, fb: "No paralelismo, os acordes não desempenham mais o seu papel funcional (T/SD/D) — cada acorde é uma cor em si. É o pensamento modal/colorista em vez do funcional/tonal." },
  { q: "Comparando substituição diatônica e tritônica: qual afirmação é verdadeira?", opts: ["A diatônica aplica-se a V7, a tritônica a todos os acordes","A substituição tritônica aplica-se especificamente a V7; a diatônica aplica-se a todos os graus","Ambas se aplicam apenas a acordes menores","A diatônica sai da escala, a tritônica não"], a: 1, fb: "A substituição tritônica mira especificamente V7 (e as dominantes secundárias). A substituição diatônica aplica-se a qualquer grau da escala." },
  { q: "Qual técnica cria o movimento do baixo mais cromático?", opts: ["Substituição diatônica","Empréstimo modal","Substituição de trítono","Harmonização paralela por tons"], a: 2, fb: "A substituição de trítono cria o movimento de baixo cromático mais direto: V7 → sub(V7) → I dá ½ tom → I (ex. Sol → Ré♭ → Dó). É a mais expressiva e a mais 'jazz'." },
  { q: "Qual técnica é a mais 'suave' (menos cromática, dentro da tonalidade)?", opts: ["Substituição de trítono","Empréstimo modal","Harmonização paralela cromática","Substituição diatônica"], a: 3, fb: "A substituição diatônica permanece inteiramente na escala — nunca sai da tonalidade. É a técnica menos cromática, a mais 'interior' à tonalidade." },
  { q: "Bill Evans nasceu e morreu em:", opts: ["1910–1975","1929–1980","1945–1990","1920–1965"], a: 1, fb: "Bill Evans (1929–1980) é um dos pianistas de jazz mais influentes do século XX. As suas inovações harmônicas — rearmonizações, voicings em clusters, empréstimos modais — definiram o piano jazz moderno." },
  { q: "Qual álbum de Miles Davis (com Bill Evans) é fundador do jazz modal?", opts: ["A Love Supreme","Kind of Blue (1959)","Bitches Brew","Sketches of Spain"], a: 1, fb: "Kind of Blue (1959) é o álbum de jazz mais vendido de todos os tempos. Bill Evans contribuiu com as notas de capa. So What, Flamenco Sketches — cada um ilustra uma abordagem modal distinta." },
  { q: "Brad Mehldau é particularmente conhecido pelas suas rearmonizações de:", opts: ["Apenas Bach e Haendel","Standards de jazz e canções pop/rock (Radiohead, Beatles)","Música de cinema","Óperas italianas"], a: 1, fb: "Brad Mehldau (nascido em 1970) é famoso pelas suas reinterpretações jazz de pop e rock — Radiohead (Exit Music for a Film), Beatles (Blackbird). As suas rearmonizações transformam estas melodias conhecidas em obras jazz sofisticadas." },
  { q: "A progressão 'Coltrane changes' (Giant Steps) usa qual princípio?", opts: ["Apenas substituições diatônicas","Um ciclo de terças maiores dividindo a oitava em 3 partes iguais","Harmonização paralela em blocos","Empréstimos modais do modo frígio"], a: 1, fb: "John Coltrane em Giant Steps (1960) divide a oitava em três terças maiores: Si – Sol – Mi♭ – Si. Cada tonalidade dura apenas 2 tempos. É uma rearmonização radical que substitui o círculo das quintas." },
  { q: "Qual pianista clássico influenciou fortemente a harmonização paralela jazz?", opts: ["Rachmaninov","Debussy (impressionismo francês)","Brahms","Bartók"], a: 1, fb: "Claude Debussy (1862–1918) influenciou diretamente o jazz através dos seus acordes paralelos, escalas por tons e cores harmônicas não funcionais. Bill Evans citava Debussy como influência principal." },
  { q: "Qual afirmação descreve melhor a rearmonização como ferramenta criativa?", opts: ["É uma técnica de correção de harmonias incorretas","É a arte de transformar a cor harmônica de uma obra respeitando a sua melodia — uma assinatura pessoal","É apenas uma técnica pedagógica","É uma técnica de simplificação para iniciantes"], a: 1, fb: "A rearmonização é uma assinatura musical pessoal. Bill Evans, Miles Davis, Keith Jarrett, Brad Mehldau — cada um desenvolveu uma linguagem reconhecível. É a arte de transformar uma obra em expressão pessoal, respeitando a melodia." },
  { q: "Para rearmonizar uma progressão gospel I–IV–I–V, qual técnica seria idiomática?", opts: ["Substituições de trítono em cada acorde","Empréstimos modais (IVm, ♭VII) para adicionar cor menor num contexto maior","Harmonização paralela cromática","Coltrane Changes"], a: 1, fb: "O gospel usa frequentemente os empréstimos modais — IVm (Fám em Dó), ♭VI, ♭VII — que introduzem a cor blues num contexto maior. A progressão I – IVm – I – V é característica do gospel." },
  { q: "Qual ilustra uma dupla técnica: empréstimo modal + harmonização paralela?", opts: ["Rem7 → Sol7 → DóMaj7","DóMaj7 → Dóm7 → Fám7 depois Fám7 → MiMaj7 → Mi♭Maj7","Sol7 → Ré♭7 → Dó","Lam7 → FáMaj7 → Sol7"], a: 1, fb: "DóMaj7 → Dóm7 → Fám7: empréstimo modal (Dó menor). Depois Fám7 → MiMaj7 → Mi♭Maj7: harmonização paralela cromática descendente. A combinação cria uma progressão muito 'Bill Evans'." },
];

